export const LEGACY_CSS: Record<string, string> = {
  "crew-manning": ".legacy-svc *, .legacy-svc *::before, .legacy-svc *::after{box-sizing:border-box;margin:0;padding:0}\n\n.legacy-svc{\n  --deep:#04181c;\n  --navy:#04181c;\n  --horizon:#07343a;\n  --blue:#0e6e78;\n  --blue-dim:rgba(14,110,120,0.12);\n  --signal:#f0a93b;\n  --signal-dk:#d68a1c;\n  --chart:#f6f1e8;\n  --light:#eef6f5;\n  --muted:#5f7b77;\n  --text:#0c4d56;\n  --body:#33514e;\n  --white:#FFFFFF;\n  --brass:#d68a1c;\n  --border:rgba(95,123,119,0.22);\n  --ff-d:'Barlow Condensed',sans-serif;\n  --ff-b:'DM Sans',sans-serif;\n  --ff-m:'Space Mono',monospace;\n  --r:4px;\n  --max:1200px;\n}\n\n.legacy-svc{scroll-behavior:smooth}\n.legacy-svc{font-family:var(--ff-b);background:var(--white);color:var(--body);line-height:1.65;overflow-x:hidden}\n\n/* в”Ђв”Ђв”Ђ UTILITIES в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n.legacy-svc .wrap{max-width:var(--max);margin:0 auto;padding:0 36px}\n.legacy-svc .eyebrow{font-family:var(--ff-m);font-size:11px;letter-spacing:.12em;text-transform:uppercase;color:var(--signal);display:block;margin-bottom:14px}\n.legacy-svc .eyebrow-b{color:var(--brass)}\n.legacy-svc .eyebrow-m{color:var(--muted)}\n\n.legacy-svc h2.dt{font-family:var(--ff-d);font-weight:800;line-height:1.05;letter-spacing:-.01em;color:var(--text)}\n.legacy-svc .dt-xl{font-size:clamp(36px,5.5vw,64px)}\n.legacy-svc .dt-lg{font-size:clamp(28px,4vw,48px)}\n\n.legacy-svc .btn{display:inline-block;font-family:var(--ff-d);font-weight:700;font-size:14px;letter-spacing:.07em;text-transform:uppercase;padding:14px 34px;border-radius:var(--r);cursor:pointer;text-decoration:none;transition:all .2s ease;border:2px solid transparent;line-height:1}\n.legacy-svc .btn-o{background:var(--signal);color:#fff}.legacy-svc .btn-o:hover{background:var(--signal-dk)}\n.legacy-svc .btn-g{border-color:rgba(255,255,255,.35);color:#fff}.legacy-svc .btn-g:hover{border-color:#fff;background:rgba(255,255,255,.08)}\n.legacy-svc .btn-w{background:#fff;color:var(--signal-dk)}.legacy-svc .btn-w:hover{background:var(--chart)}\n\n/* в”Ђв”Ђв”Ђ FADE ANIMATION в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n.legacy-svc .fu{opacity:0;transform:translateY(22px);transition:opacity .6s ease,transform .6s ease}\n.legacy-svc .fu.on{opacity:1;transform:translateY(0)}\n\n/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\n   HERO\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */\n.legacy-svc .hero{position:relative;background:var(--deep);padding:108px 0 96px;overflow:hidden}\n.legacy-svc .hero-grid{position:absolute;inset:0;background-image:linear-gradient(rgba(14,110,120,.07) 1px,transparent 1px),linear-gradient(90deg,rgba(14,110,120,.07) 1px,transparent 1px);background-size:52px 52px}\n.legacy-svc .hero-glow{position:absolute;inset:0;background:radial-gradient(ellipse 70% 55% at 55% 40%,rgba(14,110,120,.18) 0%,transparent 68%)}\n\n.legacy-svc .hero-inner{position:relative;z-index:2;display:grid;grid-template-columns:1fr 1fr;gap:60px;align-items:center}\n\n.legacy-svc .hero-hl{font-family:var(--ff-d);font-weight:800;font-size:clamp(50px,7.5vw,96px);line-height:.93;color:#fff;letter-spacing:-.025em;margin-bottom:22px}\n.legacy-svc .hero-hl em{color:var(--signal);font-style:normal;display:block}\n.legacy-svc .hero-sub{font-size:17px;color:rgba(238,246,245,.72);line-height:1.72;max-width:460px;margin-bottom:38px}\n.legacy-svc .hero-actions{display:flex;gap:14px;flex-wrap:wrap}\n\n/* Compass */\n.legacy-svc .cx{display:flex;justify-content:center;align-items:center}\n.legacy-svc .compass{position:relative;width:280px;height:280px}\n\n.legacy-svc .c-ring{position:absolute;border-radius:50%}\n.legacy-svc .c-r1{inset:0;border:1px solid rgba(14,110,120,.3);animation:spin 50s linear infinite}\n.legacy-svc .c-r1::before{content:'';position:absolute;inset:-10px;border-radius:50%;border:1px dashed rgba(14,110,120,.15)}\n.legacy-svc .c-r2{inset:28px;border:1px solid rgba(14,110,120,.2)}\n.legacy-svc .c-r3{inset:80px;border:2px solid rgba(240,169,59,.45);background:radial-gradient(circle,rgba(240,169,59,.07) 0%,transparent 70%)}\n\n@keyframes spin{to{transform:rotate(360deg)}}\n\n.legacy-svc .c-cross{position:absolute;inset:0}\n.legacy-svc .c-cross::before, .legacy-svc .c-cross::after{content:'';position:absolute;background:rgba(14,110,120,.18)}\n.legacy-svc .c-cross::before{width:100%;height:1px;top:50%}\n.legacy-svc .c-cross::after{height:100%;width:1px;left:50%}\n\n.legacy-svc .c-needle{position:absolute;inset:0;display:flex;align-items:center;justify-content:center}\n.legacy-svc .c-needle::before{content:'';position:absolute;width:2px;height:72px;background:linear-gradient(to bottom,var(--signal),transparent);bottom:50%;left:50%;transform:translateX(-50%)}\n.legacy-svc .c-needle::after{content:'';position:absolute;width:2px;height:54px;background:linear-gradient(to top,var(--muted),transparent);top:50%;left:50%;transform:translateX(-50%)}\n\n.legacy-svc .c-label{position:absolute;font-family:var(--ff-m);font-size:11px;font-weight:700;color:var(--brass)}\n.legacy-svc .c-n{top:5px;left:50%;transform:translateX(-50%)}\n.legacy-svc .c-s{bottom:5px;left:50%;transform:translateX(-50%)}\n.legacy-svc .c-e{right:5px;top:50%;transform:translateY(-50%)}\n.legacy-svc .c-w{left:5px;top:50%;transform:translateY(-50%)}\n\n.legacy-svc .c-badge{position:absolute;inset:0;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:4px;pointer-events:none}\n.legacy-svc .c-badge strong{font-family:var(--ff-d);font-size:36px;font-weight:800;color:#fff;line-height:1}\n.legacy-svc .c-badge span{font-family:var(--ff-m);font-size:10px;color:var(--muted);text-transform:uppercase;letter-spacing:.1em}\n\n/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\n   STATS STRIP\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */\n.legacy-svc .stats{background:var(--horizon);border-top:1px solid rgba(14,110,120,.2);border-bottom:1px solid rgba(14,110,120,.2);padding:30px 0}\n.legacy-svc .stats-grid{display:grid;grid-template-columns:repeat(4,1fr)}\n.legacy-svc .stat{text-align:center;padding:14px 20px;border-right:1px solid rgba(95,123,119,.18)}\n.legacy-svc .stat:last-child{border-right:none}\n.legacy-svc .stat-v{font-family:var(--ff-d);font-size:48px;font-weight:800;color:var(--signal);line-height:1;display:block}\n.legacy-svc .stat-l{font-family:var(--ff-m);font-size:10px;letter-spacing:.1em;text-transform:uppercase;color:var(--muted);margin-top:5px;display:block}\n\n/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\n   WHY MANNING MATTERS\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */\n.legacy-svc .why{padding:100px 0;background:var(--chart)}\n.legacy-svc .sec-head{text-align:center;max-width:580px;margin:0 auto 60px}\n.legacy-svc .sec-head p{margin-top:16px;font-size:16.5px;color:var(--body);line-height:1.72}\n\n.legacy-svc .wm-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:22px}\n.legacy-svc .wm-card{background:#fff;padding:36px;border-radius:6px;border-left:4px solid var(--signal);box-shadow:0 2px 14px rgba(4,24,28,.06);transition:transform .22s,box-shadow .22s}\n.legacy-svc .wm-card:hover{transform:translateY(-4px);box-shadow:0 10px 30px rgba(4,24,28,.1)}\n.legacy-svc .wm-icon{width:48px;height:48px;background:rgba(240,169,59,.1);border-radius:8px;display:flex;align-items:center;justify-content:center;margin-bottom:20px}\n.legacy-svc .wm-icon svg{width:24px;height:24px;stroke:var(--signal);fill:none;stroke-width:2;stroke-linecap:round;stroke-linejoin:round}\n.legacy-svc .wm-card h3{font-family:var(--ff-d);font-size:23px;font-weight:700;color:var(--text);margin-bottom:11px}\n.legacy-svc .wm-card p{font-size:14.5px;line-height:1.72;color:var(--body)}\n\n/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\n   SERVICES\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */\n.legacy-svc .services{padding:100px 0;background:#fff}\n.legacy-svc .svc-grid{display:grid;grid-template-columns:1fr 1fr;gap:64px;align-items:start}\n\n.legacy-svc .svc-list{list-style:none;display:flex;flex-direction:column;gap:14px}\n.legacy-svc .svc-item{padding:22px 26px;border-left:3px solid var(--border);background:var(--light);border-radius:0 4px 4px 0;transition:border-color .2s,background .2s}\n.legacy-svc .svc-item:hover{border-left-color:var(--signal);background:rgba(240,169,59,.04)}\n.legacy-svc .svc-item h4{font-family:var(--ff-d);font-size:19px;font-weight:700;color:var(--text);margin-bottom:6px}\n.legacy-svc .svc-item p{font-size:13.5px;color:var(--body);line-height:1.65}\n\n.legacy-svc .svc-box{background:var(--navy);border-radius:8px;padding:44px;color:#fff;position:sticky;top:24px}\n.legacy-svc .svc-box h3{font-family:var(--ff-d);font-size:30px;font-weight:800;color:#fff;margin-bottom:14px;line-height:1.15}\n.legacy-svc .svc-box > p{font-size:14.5px;color:rgba(238,246,245,.68);line-height:1.7;margin-bottom:30px}\n.legacy-svc .svc-feat{display:flex;align-items:center;gap:12px;padding:13px 0;border-bottom:1px solid rgba(95,123,119,.15);font-size:14px;color:rgba(238,246,245,.82)}\n.legacy-svc .svc-feat:last-of-type{border-bottom:none}\n.legacy-svc .svc-dot{width:6px;height:6px;border-radius:50%;background:var(--signal);flex-shrink:0}\n.legacy-svc .svc-box .btn-o{margin-top:28px}\n\n/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\n   VESSEL TYPES\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */\n.legacy-svc .vessels{padding:100px 0;background:var(--navy)}\n.legacy-svc .vessels .sec-head h2.dt, .legacy-svc .vessels .sec-head .eyebrow{color:#fff}\n.legacy-svc .vessels .sec-head h2.dt{color:#fff}\n.legacy-svc .vessels .sec-head .eyebrow{color:var(--brass)}\n\n.legacy-svc .vsl-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:2px;margin-top:56px;border-radius:8px;overflow:hidden}\n.legacy-svc .vsl-tile{background:rgba(255,255,255,.04);padding:34px 30px;border:1px solid rgba(95,123,119,.13);transition:background .25s}\n.legacy-svc .vsl-tile:hover{background:rgba(14,110,120,.13)}\n.legacy-svc .vsl-icon{font-size:30px;display:block;margin-bottom:15px}\n.legacy-svc .vsl-tile h3{font-family:var(--ff-d);font-size:19px;font-weight:700;color:#fff;margin-bottom:9px}\n.legacy-svc .vsl-tile p{font-size:13px;color:var(--muted);line-height:1.65}\n\n/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\n   CREW POSITIONS\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */\n.legacy-svc .positions{padding:100px 0;background:var(--chart)}\n.legacy-svc .pos-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:28px;margin-top:56px}\n.legacy-svc .dept{background:#fff;border-radius:6px;overflow:hidden;box-shadow:0 2px 14px rgba(4,24,28,.06)}\n.legacy-svc .dept-hd{padding:22px 26px;background:var(--navy);display:flex;align-items:center;gap:14px}\n.legacy-svc .dept-hd h3{font-family:var(--ff-d);font-size:21px;font-weight:700;color:#fff}\n.legacy-svc .dept-ico{width:40px;height:40px;background:rgba(240,169,59,.22);border-radius:6px;display:flex;align-items:center;justify-content:center;font-size:20px;flex-shrink:0}\n.legacy-svc .dept-body{padding:22px 26px}\n.legacy-svc .dept-body ul{list-style:none}\n.legacy-svc .dept-body li{display:flex;align-items:center;gap:10px;padding:10px 0;border-bottom:1px solid var(--light);font-size:14px;color:var(--body)}\n.legacy-svc .dept-body li:last-child{border-bottom:none}\n.legacy-svc .dept-body li::before{content:'';width:5px;height:5px;border-radius:50%;background:var(--signal);flex-shrink:0}\n\n/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\n   WHY US\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */\n.legacy-svc .why-us{padding:100px 0;background:var(--deep)}\n.legacy-svc .wu-head{text-align:center;max-width:560px;margin:0 auto 52px}\n.legacy-svc .wu-head h2.dt{color:#fff}\n\n.legacy-svc .wu-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:2px}\n.legacy-svc .wu-item{padding:38px 30px;background:rgba(255,255,255,.03);border:1px solid rgba(95,123,119,.1);transition:background .25s}\n.legacy-svc .wu-item:hover{background:rgba(14,110,120,.09)}\n.legacy-svc .wu-tag{font-family:var(--ff-m);font-size:10px;letter-spacing:.1em;text-transform:uppercase;color:var(--signal);margin-bottom:14px;display:block}\n.legacy-svc .wu-item h3{font-family:var(--ff-d);font-size:21px;font-weight:700;color:#fff;margin-bottom:9px}\n.legacy-svc .wu-item p{font-size:13.5px;color:var(--muted);line-height:1.65}\n\n/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\n   EMERGENCY\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */\n.legacy-svc .emerg{padding:84px 0;background:linear-gradient(135deg,var(--signal-dk) 0%,var(--signal) 100%)}\n.legacy-svc .emerg-inner{display:grid;grid-template-columns:1fr auto;gap:48px;align-items:center}\n.legacy-svc .emerg-badge{font-family:var(--ff-m);font-size:10px;letter-spacing:.12em;text-transform:uppercase;color:rgba(255,255,255,.7);padding:5px 14px;border:1px solid rgba(255,255,255,.35);border-radius:2px;display:inline-block;margin-bottom:16px}\n.legacy-svc .emerg h2{font-family:var(--ff-d);font-size:clamp(28px,4vw,50px);font-weight:800;color:#fff;line-height:1.08;margin-bottom:14px}\n.legacy-svc .emerg > .wrap > .emerg-inner > div > p{font-size:16px;color:rgba(255,255,255,.82);line-height:1.65;max-width:540px}\n.legacy-svc .emerg-chips{display:flex;flex-wrap:wrap;gap:10px;margin-top:26px}\n.legacy-svc .chip{background:rgba(0,0,0,.15);padding:9px 18px;border-radius:2px;font-family:var(--ff-d);font-size:13px;font-weight:600;letter-spacing:.05em;color:#fff}\n\n/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\n   BENEFITS + INDUSTRIES\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */\n.legacy-svc .benefits{padding:100px 0;background:#fff}\n.legacy-svc .ben-layout{display:grid;grid-template-columns:1fr 1fr;gap:80px;align-items:start}\n\n.legacy-svc .ben-list{list-style:none;display:flex;flex-direction:column;gap:16px;margin-top:36px}\n.legacy-svc .ben-item{display:flex;gap:14px;align-items:flex-start}\n.legacy-svc .ben-ck{width:24px;height:24px;background:var(--signal);border-radius:4px;flex-shrink:0;display:flex;align-items:center;justify-content:center;margin-top:1px}\n.legacy-svc .ben-ck svg{width:13px;height:13px;stroke:#fff;fill:none;stroke-width:2.5;stroke-linecap:round;stroke-linejoin:round}\n.legacy-svc .ben-item span{font-size:15px;color:var(--body);line-height:1.65}\n\n.legacy-svc .ind-grid{display:grid;grid-template-columns:1fr 1fr;gap:14px;margin-top:36px}\n.legacy-svc .ind-card{padding:26px;border:1px solid var(--border);border-radius:6px;transition:border-color .2s,box-shadow .2s}\n.legacy-svc .ind-card:hover{border-color:var(--signal);box-shadow:0 4px 18px rgba(240,169,59,.1)}\n.legacy-svc .ind-card-ico{font-size:26px;display:block;margin-bottom:12px}\n.legacy-svc .ind-card h4{font-family:var(--ff-d);font-size:17px;font-weight:700;color:var(--text);margin-bottom:7px}\n.legacy-svc .ind-card p{font-size:13px;color:var(--muted);line-height:1.6}\n\n/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\n   FAQ\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */\n.legacy-svc .faq{padding:100px 0;background:var(--light)}\n.legacy-svc .faq-top{margin-bottom:52px}\n.legacy-svc .faq-cols{display:grid;grid-template-columns:1fr 1fr;gap:28px;align-items:start}\n\n.legacy-svc .fq{background:#fff;border-radius:4px;overflow:hidden;margin-bottom:8px;border:1px solid var(--border)}\n.legacy-svc .fq-q{padding:20px 22px;font-family:var(--ff-d);font-size:17px;font-weight:700;color:var(--text);cursor:pointer;display:flex;justify-content:space-between;align-items:center;gap:14px;user-select:none;transition:color .18s}\n.legacy-svc .fq-q:hover{color:var(--signal)}\n.legacy-svc .fq-arr{width:20px;height:20px;flex-shrink:0;transition:transform .25s ease;stroke:var(--muted);fill:none;stroke-width:2;stroke-linecap:round;stroke-linejoin:round}\n.legacy-svc .fq.open .fq-arr{transform:rotate(180deg);stroke:var(--signal)}\n.legacy-svc .fq-a{max-height:0;overflow:hidden;transition:max-height .32s ease,padding .28s ease;font-size:14px;color:var(--body);line-height:1.72;padding:0 22px}\n.legacy-svc .fq.open .fq-a{max-height:180px;padding:0 22px 20px}\n\n/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\n   FINAL CTA\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */\n.legacy-svc .cta{padding:120px 0;background:var(--navy);position:relative;overflow:hidden}\n.legacy-svc .cta-bg{position:absolute;inset:0;background-image:linear-gradient(rgba(14,110,120,.06) 1px,transparent 1px),linear-gradient(90deg,rgba(14,110,120,.06) 1px,transparent 1px);background-size:52px 52px}\n.legacy-svc .cta-in{position:relative;z-index:2;text-align:center;max-width:680px;margin:0 auto}\n.legacy-svc .cta-in h2{font-family:var(--ff-d);font-size:clamp(36px,5.5vw,68px);font-weight:800;color:#fff;line-height:1.03;margin-bottom:18px}\n.legacy-svc .cta-in h2 em{color:var(--signal);font-style:normal}\n.legacy-svc .cta-in > p{font-size:17px;color:rgba(238,246,245,.7);line-height:1.72;margin-bottom:48px}\n.legacy-svc .cta-btns{display:flex;justify-content:center;gap:14px;flex-wrap:wrap;margin-bottom:48px}\n.legacy-svc .cta-badges{display:flex;justify-content:center;gap:28px;flex-wrap:wrap}\n.legacy-svc .cbadge{display:flex;align-items:center;gap:8px;font-family:var(--ff-m);font-size:10px;letter-spacing:.1em;text-transform:uppercase;color:var(--muted)}\n.legacy-svc .cdot{width:7px;height:7px;border-radius:50%;background:var(--signal)}\n\n/* в”Ђв”Ђв”Ђ RESPONSIVE в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n@media(max-width:960px){\n  .legacy-svc .wrap{padding:0 22px}\n  .legacy-svc .hero-inner{grid-template-columns:1fr}\n  .legacy-svc .cx{display:none}\n  .legacy-svc .hero{padding:72px 0 64px}\n  .legacy-svc .stats-grid{grid-template-columns:repeat(2,1fr)}\n  .legacy-svc .stat:nth-child(2){border-right:none}\n  .legacy-svc .wm-grid{grid-template-columns:1fr}\n  .legacy-svc .svc-grid{grid-template-columns:1fr}\n  .legacy-svc .svc-box{position:static}\n  .legacy-svc .vsl-grid{grid-template-columns:1fr 1fr}\n  .legacy-svc .pos-grid{grid-template-columns:1fr}\n  .legacy-svc .wu-grid{grid-template-columns:1fr}\n  .legacy-svc .emerg-inner{grid-template-columns:1fr}\n  .legacy-svc .ben-layout{grid-template-columns:1fr;gap:48px}\n  .legacy-svc .faq-cols{grid-template-columns:1fr}\n}\n@media(prefers-reduced-motion:reduce){\n  .legacy-svc .fu{opacity:1;transform:none}\n  .legacy-svc .c-r1{animation:none}\n}",
  "seafarer-recruitment": "/* в”Ђв”Ђ Reset в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n.legacy-svc *, .legacy-svc *::before, .legacy-svc *::after{box-sizing:border-box;margin:0;padding:0}\n.legacy-svc{scroll-behavior:smooth}\n.legacy-svc ul, .legacy-svc ol{list-style:none}\n.legacy-svc a{text-decoration:none}\n.legacy-svc button{font-family:inherit;cursor:pointer}\n\n/* в”Ђв”Ђ Design Tokens в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n.legacy-svc{\n  --navy:    #07343a;\n  --navy-m:  #0c4d56;\n  --navy-l:  #0c5760;\n  --orange:  #f0a93b;\n  --orange-d:#d68a1c;\n  --amber:   #f6b53f;\n  --steel:   #eef6f5;\n  --white:   #FFFFFF;\n  --text:    #0b2a2e;\n  --text-m:  #33514e;\n  --text-l:  #5f7b77;\n  --border:  #d8e7e3;\n  --fd:'Barlow Condensed',sans-serif;\n  --fb:'Inter',sans-serif;\n  --xl:100px;\n}\n\n.legacy-svc{font-family:var(--fb);color:var(--text);background:var(--white);font-size:16px;line-height:1.6;-webkit-font-smoothing:antialiased}\n\n/* в”Ђв”Ђ Utilities в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n.legacy-svc .wrap{max-width:1160px;margin:0 auto;padding:0 24px}\n\n.legacy-svc .eyebrow{font-size:11px;font-weight:600;letter-spacing:.14em;text-transform:uppercase;color:var(--orange);display:block;margin-bottom:14px}\n.legacy-svc .eyebrow-amber{color:var(--amber)}\n\n.legacy-svc .hdisplay{font-family:var(--fd);font-weight:800;font-size:clamp(2rem,4.5vw,3.2rem);line-height:1.02;text-transform:uppercase;letter-spacing:-.01em;color:var(--text)}\n.legacy-svc .hdisplay-white{color:var(--white)}\n\n.legacy-svc .subtext{font-size:16px;line-height:1.68;color:var(--text-m);max-width:640px}\n.legacy-svc .subtext-light{color:rgba(255,255,255,.66)}\n\n/* Compass-diamond divider вЂ” signature element */\n.legacy-svc .cdiv{display:flex;align-items:center;gap:10px;margin-bottom:36px}\n.legacy-svc .cdiv::before, .legacy-svc .cdiv::after{content:'';width:44px;height:1.5px;background:var(--orange)}\n.legacy-svc .cdiv-gem{width:7px;height:7px;background:var(--orange);transform:rotate(45deg);flex-shrink:0}\n\n/* Center-aligned section header */\n.legacy-svc .s-ctr{text-align:center}\n.legacy-svc .s-ctr .cdiv{margin-left:auto;margin-right:auto;width:fit-content}\n.legacy-svc .s-ctr .subtext{margin:16px auto 0}\n\n/* Buttons */\n.legacy-svc .btn{display:inline-flex;align-items:center;gap:7px;padding:14px 28px;border-radius:3px;font-family:var(--fb);font-weight:600;font-size:14.5px;border:none;transition:all .2s;line-height:1}\n.legacy-svc .btn-solid{background:var(--orange);color:#fff}\n.legacy-svc .btn-solid:hover{background:var(--orange-d);transform:translateY(-1px)}\n.legacy-svc .btn-ghost{background:transparent;color:#fff;border:1.5px solid rgba(255,255,255,.34)}\n.legacy-svc .btn-ghost:hover{border-color:#fff;background:rgba(255,255,255,.07)}\n\n/* в”Ђв”Ђ HERO в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n.legacy-svc .hero{\n  background-color:var(--navy);\n  background-image:radial-gradient(ellipse 72% 90% at 88% 45%,rgba(14,110,120,.55) 0%,transparent 65%),radial-gradient(ellipse 30% 35% at 4% 85%,rgba(240,169,59,.05) 0%,transparent 55%);\n  padding:96px 0 80px;\n  position:relative;\n}\n\n.legacy-svc .hero-badge{display:inline-flex;align-items:center;gap:8px;background:rgba(240,169,59,.14);border:1px solid rgba(240,169,59,.28);border-radius:2px;padding:7px 14px;font-size:11px;font-weight:600;letter-spacing:.1em;text-transform:uppercase;color:var(--amber);margin-bottom:22px}\n\n.legacy-svc .hero-title{font-family:var(--fd);font-size:clamp(4rem,11vw,8.2rem);font-weight:800;text-transform:uppercase;line-height:.90;letter-spacing:-.02em;color:#fff;margin-bottom:28px}\n.legacy-svc .hero-title .hl{color:var(--orange);display:block}\n\n.legacy-svc .hero-desc{font-size:16.5px;line-height:1.65;color:rgba(255,255,255,.70);max-width:540px;margin-bottom:38px}\n\n.legacy-svc .hero-btns{display:flex;gap:12px;flex-wrap:wrap;margin-bottom:56px}\n\n.legacy-svc .cert-strip{display:flex;align-items:center;gap:20px;flex-wrap:wrap}\n.legacy-svc .cert-label{font-size:10.5px;font-weight:600;letter-spacing:.12em;text-transform:uppercase;color:rgba(255,255,255,.32)}\n.legacy-svc .cert-badges{display:flex;align-items:center;gap:7px;flex-wrap:wrap}\n.legacy-svc .cert-badge{padding:5px 11px;border:1px solid rgba(255,255,255,.16);border-radius:2px;font-size:10.5px;font-weight:600;letter-spacing:.07em;color:rgba(255,255,255,.58)}\n\n/* в”Ђв”Ђ STATS BAR в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n.legacy-svc .stats-bar{background:var(--orange);padding:22px 0}\n.legacy-svc .stats-inner{display:grid;grid-template-columns:repeat(4,1fr)}\n.legacy-svc .stat-item{text-align:center;padding:6px 12px;border-right:1px solid rgba(255,255,255,.22)}\n.legacy-svc .stat-item:last-child{border-right:none}\n.legacy-svc .stat-n{font-family:var(--fd);font-size:2.1rem;font-weight:800;color:#fff;line-height:1}\n.legacy-svc .stat-l{font-size:10.5px;font-weight:600;color:rgba(255,255,255,.86);text-transform:uppercase;letter-spacing:.07em;margin-top:4px}\n\n/* в”Ђв”Ђ WHY PROFESSIONAL в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n.legacy-svc .sec-why{padding:var(--xl) 0;background:var(--white)}\n\n.legacy-svc .why-layout{display:grid;grid-template-columns:1fr 1.28fr;gap:60px;align-items:start}\n\n.legacy-svc .b2col{display:grid;grid-template-columns:1fr 1fr;gap:14px;margin-top:26px}\n.legacy-svc .b-item{display:flex;align-items:flex-start;gap:10px}\n.legacy-svc .b-ico{flex-shrink:0;width:17px;height:17px;color:var(--orange);margin-top:3px}\n.legacy-svc .b-title{font-size:13px;font-weight:600;color:var(--text);display:block;margin-bottom:1px}\n.legacy-svc .b-desc{font-size:12.5px;color:var(--text-m);line-height:1.44}\n\n.legacy-svc .risk-row{display:grid;grid-template-columns:repeat(3,1fr);gap:18px;margin-top:52px}\n.legacy-svc .risk-card{border:1.5px solid var(--border);border-top:3px solid var(--orange);border-radius:3px;padding:20px}\n.legacy-svc .risk-title{font-size:11.5px;font-weight:700;text-transform:uppercase;letter-spacing:.06em;color:var(--text);margin-bottom:7px}\n.legacy-svc .risk-desc{font-size:13px;color:var(--text-m);line-height:1.5}\n\n/* в”Ђв”Ђ SERVICES в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n.legacy-svc .sec-services{padding:var(--xl) 0;background:var(--navy)}\n.legacy-svc .sec-services .subtext{color:rgba(255,255,255,.62)}\n\n.legacy-svc .svc-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:1px;background:rgba(255,255,255,.06);border:1px solid rgba(255,255,255,.06);border-radius:6px;overflow:hidden;margin-top:48px}\n.legacy-svc .svc-card{background:var(--navy-m);padding:28px 22px;transition:background .2s}\n.legacy-svc .svc-card:hover{background:var(--navy-l)}\n.legacy-svc .svc-ico{width:33px;height:33px;color:var(--orange);margin-bottom:14px}\n.legacy-svc .svc-title{font-family:var(--fd);font-size:1.12rem;font-weight:700;text-transform:uppercase;letter-spacing:.03em;color:#fff;margin-bottom:8px}\n.legacy-svc .svc-desc{font-size:13px;color:rgba(255,255,255,.56);line-height:1.54}\n\n/* в”Ђв”Ђ VESSELS в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n.legacy-svc .sec-vessels{padding:var(--xl) 0;background:var(--steel)}\n\n.legacy-svc .vess-grid{display:grid;grid-template-columns:repeat(5,1fr);gap:14px;margin-top:48px}\n.legacy-svc .vess-card{background:var(--white);border:1.5px solid var(--border);border-radius:5px;padding:20px 14px;text-align:center;transition:all .2s;cursor:default}\n.legacy-svc .vess-card:hover{border-color:var(--orange);box-shadow:0 4px 18px rgba(240,169,59,.10);transform:translateY(-2px)}\n.legacy-svc .vess-ico{font-size:1.85rem;margin-bottom:10px;display:block}\n.legacy-svc .vess-name{font-family:var(--fd);font-size:.95rem;font-weight:700;text-transform:uppercase;letter-spacing:.04em;color:var(--text);margin-bottom:6px}\n.legacy-svc .vess-desc{font-size:11.5px;color:var(--text-l);line-height:1.5}\n\n/* в”Ђв”Ђ POSITIONS в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n.legacy-svc .sec-pos{padding:var(--xl) 0;background:var(--white)}\n\n.legacy-svc .pos-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:32px;margin-top:48px}\n.legacy-svc .pos-dept{border-top:3px solid var(--orange);padding-top:24px}\n.legacy-svc .dept-hd{font-family:var(--fd);font-size:1.05rem;font-weight:700;text-transform:uppercase;letter-spacing:.07em;color:var(--text);margin-bottom:18px;display:flex;align-items:center;gap:9px}\n.legacy-svc .dept-hd svg{width:19px;height:19px;color:var(--orange);flex-shrink:0}\n.legacy-svc .pos-list li{padding:12px 0;border-bottom:1px solid var(--border)}\n.legacy-svc .pos-list li:last-child{border-bottom:none}\n.legacy-svc .pos-rank{font-size:13.5px;font-weight:600;color:var(--text);margin-bottom:3px}\n.legacy-svc .pos-desc{font-size:12px;color:var(--text-m);line-height:1.45}\n\n/* в”Ђв”Ђ QUALITY в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n.legacy-svc .sec-quality{padding:var(--xl) 0;background:var(--navy)}\n.legacy-svc .sec-quality .subtext{color:rgba(255,255,255,.62)}\n\n.legacy-svc .q-grid{display:grid;grid-template-columns:1fr 1fr;gap:14px;margin-top:48px}\n.legacy-svc .q-item{display:flex;align-items:flex-start;gap:16px;padding:20px 22px;background:rgba(255,255,255,.04);border:1px solid rgba(255,255,255,.07);border-radius:5px;transition:background .2s}\n.legacy-svc .q-item:hover{background:rgba(255,255,255,.065)}\n.legacy-svc .q-num{font-family:var(--fd);font-size:2.3rem;font-weight:800;color:rgba(240,169,59,.26);line-height:1;flex-shrink:0;width:46px}\n.legacy-svc .q-title{font-size:13px;font-weight:700;text-transform:uppercase;letter-spacing:.05em;color:#fff;margin-bottom:4px}\n.legacy-svc .q-desc{font-size:12.5px;color:rgba(255,255,255,.52);line-height:1.5}\n\n/* в”Ђв”Ђ EMERGENCY в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n.legacy-svc .sec-emg{padding:var(--xl) 0;background:#04181c;border-top:3px solid var(--orange)}\n\n.legacy-svc .emg-inner{display:grid;grid-template-columns:1fr 1fr;gap:72px;align-items:start}\n.legacy-svc .emg-tagline{font-family:var(--fd);font-size:1.65rem;font-weight:700;text-transform:uppercase;color:var(--orange);margin:22px 0 26px;letter-spacing:.04em}\n\n.legacy-svc .bul-list li{display:flex;align-items:flex-start;gap:10px;padding:9px 0;border-bottom:1px solid rgba(255,255,255,.06);font-size:14px;color:rgba(255,255,255,.72)}\n.legacy-svc .bul-list li:last-child{border-bottom:none}\n.legacy-svc .bul-list li::before{content:'в–ё';color:var(--orange);flex-shrink:0;font-size:11px;margin-top:3px}\n\n.legacy-svc .emg-sublabel{font-size:10px;font-weight:700;letter-spacing:.13em;text-transform:uppercase;color:rgba(255,255,255,.32);margin-bottom:10px;display:block}\n\n.legacy-svc .res-box{background:rgba(240,169,59,.07);border:1px solid rgba(240,169,59,.22);border-radius:5px;padding:26px}\n.legacy-svc .res-title{font-family:var(--fd);font-size:1.05rem;font-weight:700;text-transform:uppercase;letter-spacing:.07em;color:var(--amber);margin-bottom:18px}\n.legacy-svc .emg-note{margin-top:20px;font-size:13px;color:rgba(255,255,255,.38);line-height:1.6}\n\n/* в”Ђв”Ђ OUTSOURCE BENEFITS в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n.legacy-svc .sec-out{padding:var(--xl) 0;background:var(--white)}\n\n.legacy-svc .out-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:16px;margin-top:48px}\n.legacy-svc .out-item{display:flex;gap:13px;padding:18px;border:1.5px solid var(--border);border-radius:5px;align-items:flex-start;transition:border-color .2s}\n.legacy-svc .out-item:hover{border-color:var(--orange)}\n.legacy-svc .out-ico{width:18px;height:18px;color:var(--orange);flex-shrink:0;margin-top:2px}\n.legacy-svc .out-title{font-size:13px;font-weight:600;color:var(--text);margin-bottom:3px}\n.legacy-svc .out-desc{font-size:12px;color:var(--text-m);line-height:1.5}\n\n/* в”Ђв”Ђ INDUSTRIES в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n.legacy-svc .sec-ind{padding:var(--xl) 0;background:var(--steel)}\n\n.legacy-svc .ind-inner{display:grid;grid-template-columns:1fr 1fr;gap:40px;margin-top:48px}\n.legacy-svc .ind-title{font-family:var(--fd);font-size:1rem;font-weight:700;text-transform:uppercase;letter-spacing:.07em;color:var(--navy);margin-bottom:16px;padding-bottom:10px;border-bottom:2px solid var(--orange)}\n.legacy-svc .tag-cloud{display:flex;flex-wrap:wrap;gap:8px}\n.legacy-svc .tag{padding:6px 13px;background:var(--white);border:1.5px solid var(--border);border-radius:2px;font-size:13px;font-weight:500;color:var(--text);transition:all .2s;cursor:default}\n.legacy-svc .tag:hover{border-color:var(--orange);color:var(--orange)}\n\n/* в”Ђв”Ђ WHY CHOOSE в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n.legacy-svc .sec-choose{padding:var(--xl) 0;background:var(--white)}\n\n.legacy-svc .ch-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:18px;margin-top:48px}\n.legacy-svc .ch-card{padding:22px;border:1.5px solid var(--border);border-radius:5px;transition:all .2s}\n.legacy-svc .ch-card:hover{border-color:var(--orange);box-shadow:0 4px 18px rgba(240,169,59,.07)}\n.legacy-svc .ch-icon{width:36px;height:36px;background:rgba(240,169,59,.08);border-radius:5px;display:flex;align-items:center;justify-content:center;color:var(--orange);margin-bottom:14px}\n.legacy-svc .ch-title{font-size:14px;font-weight:700;color:var(--text);margin-bottom:6px}\n.legacy-svc .ch-desc{font-size:12.5px;color:var(--text-m);line-height:1.54}\n\n/* в”Ђв”Ђ FAQ в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n.legacy-svc .sec-faq{padding:var(--xl) 0;background:var(--steel)}\n\n.legacy-svc .faq-list{max-width:780px;margin:48px auto 0}\n.legacy-svc .faq-item{border-bottom:1px solid var(--border)}\n.legacy-svc .faq-item:first-child{border-top:1px solid var(--border)}\n.legacy-svc .faq-btn{width:100%;background:none;border:none;display:flex;align-items:center;justify-content:space-between;gap:16px;padding:19px 0;text-align:left;font-family:var(--fb);font-size:14.5px;font-weight:600;color:var(--text);transition:color .2s}\n.legacy-svc .faq-btn:hover, .legacy-svc .faq-btn.open{color:var(--orange)}\n.legacy-svc .faq-ico{width:17px;height:17px;flex-shrink:0;color:var(--orange);transition:transform .25s ease}\n.legacy-svc .faq-btn.open .faq-ico{transform:rotate(45deg)}\n.legacy-svc .faq-body{overflow:hidden;max-height:0;transition:max-height .32s ease}\n.legacy-svc .faq-body.open{max-height:500px}\n.legacy-svc .faq-ans{font-size:13.5px;color:var(--text-m);line-height:1.66;padding-bottom:18px;padding-right:32px}\n\n/* в”Ђв”Ђ CTA в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n.legacy-svc .sec-cta{padding:var(--xl) 0;background:var(--navy);position:relative;overflow:hidden}\n.legacy-svc .sec-cta::before{content:'';position:absolute;top:-60px;right:-60px;width:360px;height:360px;background:radial-gradient(circle,rgba(240,169,59,.09) 0%,transparent 68%);pointer-events:none}\n\n.legacy-svc .cta-grid{display:grid;grid-template-columns:1fr 1fr;gap:72px;align-items:start;position:relative;z-index:1}\n.legacy-svc .cta-left .hdisplay{color:#fff;margin-bottom:14px}\n.legacy-svc .cta-left p{font-size:14.5px;color:rgba(255,255,255,.62);line-height:1.65;margin-bottom:18px}\n.legacy-svc .cta-left .btn{margin-top:6px}\n\n.legacy-svc .fw{display:grid;gap:13px}\n.legacy-svc .frow{display:grid;grid-template-columns:1fr 1fr;gap:13px}\n.legacy-svc .fg label{display:block;font-size:11px;font-weight:600;letter-spacing:.09em;text-transform:uppercase;color:rgba(255,255,255,.42);margin-bottom:6px}\n.legacy-svc .fg input, .legacy-svc .fg select, .legacy-svc .fg textarea{width:100%;background:rgba(255,255,255,.06);border:1px solid rgba(255,255,255,.14);border-radius:3px;padding:11px 13px;font-family:var(--fb);font-size:14px;color:#fff;outline:none;transition:border-color .2s;-webkit-appearance:none}\n.legacy-svc .fg input::placeholder, .legacy-svc .fg textarea::placeholder{color:rgba(255,255,255,.22)}\n.legacy-svc .fg input:focus, .legacy-svc .fg select:focus, .legacy-svc .fg textarea:focus{border-color:rgba(240,169,59,.60)}\n.legacy-svc .fg select option{background:var(--navy-m);color:#fff}\n.legacy-svc .fg textarea{resize:vertical;min-height:76px}\n.legacy-svc .form-btn{width:100%;background:var(--orange);color:#fff;border:none;border-radius:3px;padding:14px;font-family:var(--fb);font-size:14.5px;font-weight:600;transition:background .2s}\n.legacy-svc .form-btn:hover{background:var(--orange-d)}\n\n.legacy-svc .form-success{display:none;text-align:center;padding:36px 24px;background:rgba(240,169,59,.09);border:1px solid rgba(240,169,59,.28);border-radius:5px}\n.legacy-svc .fs-ico{font-size:2rem;margin-bottom:10px}\n.legacy-svc .fs-title{font-family:var(--fd);font-size:1.6rem;font-weight:800;text-transform:uppercase;color:#fff;margin-bottom:8px}\n.legacy-svc .fs-msg{font-size:13.5px;color:rgba(255,255,255,.62)}\n\n/* в”Ђв”Ђ Responsive в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n@media(max-width:1024px){\n  .legacy-svc .svc-grid{grid-template-columns:repeat(2,1fr)}\n  .legacy-svc .vess-grid{grid-template-columns:repeat(3,1fr)}\n  .legacy-svc .ch-grid{grid-template-columns:repeat(2,1fr)}\n  .legacy-svc .stats-inner{grid-template-columns:repeat(2,1fr)}\n  .legacy-svc .stat-item:nth-child(2){border-right:none}\n}\n@media(max-width:768px){\n  .legacy-svc{--xl:68px}\n  .legacy-svc .hero{padding:68px 0 56px}\n  .legacy-svc .why-layout{grid-template-columns:1fr;gap:36px}\n  .legacy-svc .b2col{grid-template-columns:1fr}\n  .legacy-svc .risk-row{grid-template-columns:1fr}\n  .legacy-svc .svc-grid{grid-template-columns:1fr}\n  .legacy-svc .vess-grid{grid-template-columns:repeat(2,1fr)}\n  .legacy-svc .pos-grid{grid-template-columns:1fr}\n  .legacy-svc .q-grid{grid-template-columns:1fr}\n  .legacy-svc .emg-inner{grid-template-columns:1fr;gap:40px}\n  .legacy-svc .out-grid{grid-template-columns:1fr 1fr}\n  .legacy-svc .ind-inner{grid-template-columns:1fr;gap:28px}\n  .legacy-svc .ch-grid{grid-template-columns:1fr}\n  .legacy-svc .cta-grid{grid-template-columns:1fr;gap:48px}\n  .legacy-svc .frow{grid-template-columns:1fr}\n}\n@media(max-width:480px){\n  .legacy-svc .vess-grid{grid-template-columns:repeat(2,1fr)}\n  .legacy-svc .out-grid{grid-template-columns:1fr}\n  .legacy-svc .stats-inner{grid-template-columns:repeat(2,1fr)}\n}\n@media(prefers-reduced-motion:reduce){\n  .legacy-svc *, .legacy-svc *::before, .legacy-svc *::after{transition:none!important;animation:none!important}\n}",
  "crew-replacement": ".legacy-svc *, .legacy-svc *::before, .legacy-svc *::after{box-sizing:border-box;margin:0;padding:0}\n\n.legacy-svc{\n  --deep:#04181c;\n  --navy:#04181c;\n  --hor:#07343a;\n  --blue:#0e6e78;\n  --blu12:rgba(14,110,120,.12);\n  --signal:#f0a93b;\n  --sig-dk:#d68a1c;\n  --chart:#f6f1e8;\n  --light:#eef6f5;\n  --muted:#5f7b77;\n  --text:#0c4d56;\n  --body:#33514e;\n  --white:#FFFFFF;\n  --brass:#d68a1c;\n  --bdr:rgba(95,123,119,.22);\n  --ff-d:'Barlow Condensed',sans-serif;\n  --ff-b:'DM Sans',sans-serif;\n  --ff-m:'Space Mono',monospace;\n  --max:1200px;\n  --r:4px;\n}\n\n.legacy-svc{scroll-behavior:smooth}\n.legacy-svc{font-family:var(--ff-b);background:#fff;color:var(--body);line-height:1.65;overflow-x:hidden}\n\n/* в”Ђв”Ђв”Ђ UTILS в”Ђв”Ђв”Ђ */\n.legacy-svc .w{max-width:var(--max);margin:0 auto;padding:0 36px}\n.legacy-svc .eb{font-family:var(--ff-m);font-size:11px;letter-spacing:.12em;text-transform:uppercase;display:block;margin-bottom:14px}\n.legacy-svc .eb-o{color:var(--signal)}\n.legacy-svc .eb-b{color:var(--brass)}\n.legacy-svc .eb-m{color:var(--muted)}\n.legacy-svc h2.d{font-family:var(--ff-d);font-weight:800;line-height:1.05;letter-spacing:-.01em;color:var(--text)}\n.legacy-svc .d-xl{font-size:clamp(40px,6vw,82px)}\n.legacy-svc .d-lg{font-size:clamp(28px,4vw,50px)}\n.legacy-svc .d-md{font-size:clamp(22px,3vw,36px)}\n\n.legacy-svc .btn{display:inline-block;font-family:var(--ff-d);font-weight:700;font-size:14px;letter-spacing:.07em;text-transform:uppercase;padding:14px 34px;border-radius:var(--r);text-decoration:none;transition:all .2s;border:2px solid transparent;cursor:pointer;line-height:1}\n.legacy-svc .bto{background:var(--signal);color:#fff}.legacy-svc .bto:hover{background:var(--sig-dk)}\n.legacy-svc .btg{border-color:rgba(255,255,255,.35);color:#fff}.legacy-svc .btg:hover{border-color:#fff;background:rgba(255,255,255,.08)}\n.legacy-svc .btw{background:#fff;color:var(--sig-dk)}.legacy-svc .btw:hover{background:var(--chart)}\n.legacy-svc .btn-dk{background:var(--deep);color:#fff;border-color:var(--deep)}.legacy-svc .btn-dk:hover{background:var(--navy)}\n\n/* в”Ђв”Ђв”Ђ ANIMATION в”Ђв”Ђв”Ђ */\n.legacy-svc .fu{opacity:0;transform:translateY(22px);transition:opacity .6s ease,transform .6s ease}\n.legacy-svc .fu.on{opacity:1;transform:translateY(0)}\n\n/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\n   HERO\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */\n.legacy-svc .hero{position:relative;background:var(--deep);padding:108px 0 96px;overflow:hidden}\n.legacy-svc .h-grid{position:absolute;inset:0;\n  background-image:linear-gradient(rgba(14,110,120,.07) 1px,transparent 1px),\n    linear-gradient(90deg,rgba(14,110,120,.07) 1px,transparent 1px);\n  background-size:52px 52px}\n.legacy-svc .h-glow{position:absolute;inset:0;background:radial-gradient(ellipse 65% 50% at 55% 40%,rgba(14,110,120,.16) 0%,transparent 70%)}\n\n.legacy-svc .hero-wrap{position:relative;z-index:2;display:grid;grid-template-columns:1fr 1fr;gap:60px;align-items:center}\n\n.legacy-svc .hero-lede{font-family:var(--ff-m);font-size:11px;letter-spacing:.12em;text-transform:uppercase;color:var(--signal);display:block;margin-bottom:16px}\n.legacy-svc .hero-hl{font-family:var(--ff-d);font-weight:800;font-size:clamp(44px,7vw,88px);line-height:.93;color:#fff;letter-spacing:-.025em;margin-bottom:22px}\n.legacy-svc .hero-hl em{color:var(--signal);font-style:normal;display:block}\n.legacy-svc .hero-sub{font-size:17px;color:rgba(238,246,245,.72);line-height:1.72;max-width:460px;margin-bottom:38px}\n.legacy-svc .hero-acts{display:flex;gap:14px;flex-wrap:wrap}\n\n/* Radar visual */\n.legacy-svc .radar-wrap{display:flex;justify-content:center;align-items:center}\n.legacy-svc .radar{position:relative;width:280px;height:280px}\n.legacy-svc .rd-ring{position:absolute;border-radius:50%}\n.legacy-svc .rd-r1{inset:0;border:1px solid rgba(14,110,120,.25)}\n.legacy-svc .rd-r2{inset:22%;border:1px solid rgba(14,110,120,.2)}\n.legacy-svc .rd-r3{inset:44%;border:1px solid rgba(14,110,120,.18)}\n.legacy-svc .rd-r4{inset:64%;border:2px solid rgba(240,169,59,.45);background:radial-gradient(circle,rgba(240,169,59,.08) 0%,transparent 70%)}\n.legacy-svc .rd-cx, .legacy-svc .rd-cy{position:absolute;background:rgba(14,110,120,.15)}\n.legacy-svc .rd-cx{height:1px;width:100%;top:50%}\n.legacy-svc .rd-cy{width:1px;height:100%;left:50%}\n.legacy-svc .rd-sweep{position:absolute;inset:0;border-radius:50%;\n  background:conic-gradient(from 0deg,transparent 0deg,rgba(14,110,120,.22) 28deg,rgba(14,110,120,.06) 55deg,transparent 55deg);\n  animation:rdspin 3.2s linear infinite}\n@keyframes rdspin{to{transform:rotate(360deg)}}\n.legacy-svc .rd-blip{position:absolute;width:8px;height:8px;border-radius:50%;background:var(--signal)}\n.legacy-svc .rd-b1{top:22%;left:62%}\n.legacy-svc .rd-b2{top:58%;left:28%}\n.legacy-svc .rd-b3{top:72%;left:67%}\n.legacy-svc .rd-blip::after{content:'';position:absolute;inset:-4px;border-radius:50%;border:2px solid var(--signal);animation:rdping 2.4s ease-out infinite;opacity:0}\n.legacy-svc .rd-b1::after{animation-delay:0s}\n.legacy-svc .rd-b2::after{animation-delay:.8s}\n.legacy-svc .rd-b3::after{animation-delay:1.6s}\n@keyframes rdping{0%{transform:scale(1);opacity:.8}100%{transform:scale(3);opacity:0}}\n.legacy-svc .rd-badge{position:absolute;inset:0;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:5px;pointer-events:none}\n.legacy-svc .rd-badge strong{font-family:var(--ff-d);font-size:34px;font-weight:800;color:#fff;line-height:1}\n.legacy-svc .rd-badge span{font-family:var(--ff-m);font-size:10px;color:var(--signal);text-transform:uppercase;letter-spacing:.12em}\n\n/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\n   STATS\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */\n.legacy-svc .stats{background:var(--hor);border-top:1px solid rgba(14,110,120,.2);border-bottom:1px solid rgba(14,110,120,.2);padding:30px 0}\n.legacy-svc .stats-g{display:grid;grid-template-columns:repeat(4,1fr)}\n.legacy-svc .st{text-align:center;padding:14px 20px;border-right:1px solid rgba(95,123,119,.18)}\n.legacy-svc .st:last-child{border-right:none}\n.legacy-svc .stv{font-family:var(--ff-d);font-size:48px;font-weight:800;color:var(--signal);line-height:1;display:block}\n.legacy-svc .stl{font-family:var(--ff-m);font-size:10px;letter-spacing:.1em;text-transform:uppercase;color:var(--muted);margin-top:5px;display:block}\n\n/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\n   WHY IT MATTERS\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */\n.legacy-svc .why{padding:100px 0;background:var(--navy)}\n.legacy-svc .why-hd{max-width:580px;margin:0 auto 56px;text-align:center}\n.legacy-svc .why-hd h2.d{color:#fff}\n.legacy-svc .why-hd p{margin-top:16px;font-size:16px;color:rgba(238,246,245,.65);line-height:1.72}\n\n.legacy-svc .why-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:2px}\n.legacy-svc .wc{background:rgba(255,255,255,.04);border:1px solid rgba(95,123,119,.12);padding:32px 28px;transition:background .25s}\n.legacy-svc .wc:hover{background:rgba(14,110,120,.1)}\n.legacy-svc .wc-tag{font-family:var(--ff-m);font-size:10px;letter-spacing:.12em;text-transform:uppercase;color:var(--signal);display:block;margin-bottom:10px}\n.legacy-svc .wc h3{font-family:var(--ff-d);font-size:21px;font-weight:700;color:#fff;margin-bottom:10px;border-top:2px solid var(--signal);padding-top:14px}\n.legacy-svc .wc p{font-size:13.5px;color:var(--muted);line-height:1.68}\n\n/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\n   SERVICES\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */\n.legacy-svc .services{padding:100px 0;background:var(--chart)}\n.legacy-svc .svc-hd{max-width:640px;margin-bottom:52px}\n\n/* Featured: Emergency */\n.legacy-svc .svc-featured{background:var(--navy);border-radius:8px;padding:44px 48px;margin-bottom:24px;display:grid;grid-template-columns:1fr 1fr;gap:48px;align-items:center;border-left:5px solid var(--signal)}\n.legacy-svc .sf-l .stag{font-family:var(--ff-m);font-size:10px;letter-spacing:.12em;text-transform:uppercase;color:var(--signal);padding:5px 14px;border:1px solid rgba(240,169,59,.4);border-radius:2px;display:inline-block;margin-bottom:18px}\n.legacy-svc .sf-l h3{font-family:var(--ff-d);font-size:30px;font-weight:800;color:#fff;line-height:1.1;margin-bottom:14px}\n.legacy-svc .sf-l p{font-size:15px;color:rgba(238,246,245,.7);line-height:1.7;margin-bottom:24px}\n.legacy-svc .sf-r{display:flex;flex-direction:column;gap:10px}\n.legacy-svc .sf-chip{background:rgba(255,255,255,.06);border:1px solid rgba(95,123,119,.2);padding:12px 18px;border-radius:4px;display:flex;align-items:center;gap:12px;font-size:14px;color:rgba(238,246,245,.85)}\n.legacy-svc .sf-chip-dot{width:6px;height:6px;border-radius:50%;background:var(--signal);flex-shrink:0}\n\n.legacy-svc .svc-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:16px}\n.legacy-svc .sc{background:#fff;border-radius:6px;padding:28px;border-left:3px solid var(--bdr);box-shadow:0 2px 10px rgba(4,24,28,.05);transition:border-color .2s,transform .2s,box-shadow .2s}\n.legacy-svc .sc:hover{border-left-color:var(--signal);transform:translateY(-3px);box-shadow:0 8px 24px rgba(4,24,28,.1)}\n.legacy-svc .sc h3{font-family:var(--ff-d);font-size:19px;font-weight:700;color:var(--text);margin-bottom:8px}\n.legacy-svc .sc p{font-size:13.5px;color:var(--body);line-height:1.65}\n\n/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\n   POSITIONS\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */\n.legacy-svc .positions{padding:100px 0;background:#fff}\n.legacy-svc .pos-hd{text-align:center;max-width:580px;margin:0 auto 52px}\n\n.legacy-svc .pos-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:24px}\n.legacy-svc .dept{background:#fff;border-radius:8px;overflow:hidden;box-shadow:0 2px 14px rgba(4,24,28,.07);border:1px solid var(--bdr)}\n.legacy-svc .dept-h{padding:22px 26px;background:var(--navy);display:flex;align-items:center;gap:14px}\n.legacy-svc .dept-h h3{font-family:var(--ff-d);font-size:21px;font-weight:700;color:#fff}\n.legacy-svc .dept-ico{width:40px;height:40px;background:rgba(240,169,59,.2);border-radius:6px;display:flex;align-items:center;justify-content:center;font-size:20px;flex-shrink:0}\n.legacy-svc .dept-body{padding:16px 24px 22px}\n.legacy-svc .role-item{padding:12px 0;border-bottom:1px solid var(--light)}\n.legacy-svc .role-item:last-child{border-bottom:none}\n.legacy-svc .role-name{font-family:var(--ff-d);font-size:16px;font-weight:700;color:var(--text);display:flex;align-items:center;gap:8px;margin-bottom:4px}\n.legacy-svc .role-name::before{content:'';width:5px;height:5px;border-radius:50%;background:var(--signal);flex-shrink:0}\n.legacy-svc .role-desc{font-size:12.5px;color:var(--muted);line-height:1.6;padding-left:13px}\n\n/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\n   VESSEL TYPES\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */\n.legacy-svc .vessels{padding:100px 0;background:var(--deep)}\n.legacy-svc .vsl-hd{max-width:580px;margin-bottom:52px}\n.legacy-svc .vsl-hd h2.d{color:#fff}\n\n.legacy-svc .vsl-grid{display:grid;grid-template-columns:1fr 1fr;gap:2px}\n.legacy-svc .vt{display:flex;align-items:flex-start;gap:18px;padding:24px 28px;background:rgba(255,255,255,.04);border:1px solid rgba(95,123,119,.1);transition:background .25s}\n.legacy-svc .vt:hover{background:rgba(14,110,120,.1)}\n.legacy-svc .vt-ico{font-size:28px;flex-shrink:0;line-height:1;margin-top:2px}\n.legacy-svc .vt-content h3{font-family:var(--ff-d);font-size:18px;font-weight:700;color:#fff;margin-bottom:6px}\n.legacy-svc .vt-content p{font-size:13px;color:var(--muted);line-height:1.6}\n\n/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\n   EMERGENCY STRIP\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */\n.legacy-svc .emerg{padding:84px 0;background:linear-gradient(135deg,var(--sig-dk) 0%,var(--signal) 100%)}\n.legacy-svc .emerg-in{display:grid;grid-template-columns:1fr 1fr;gap:64px;align-items:start}\n.legacy-svc .emerg-b{font-family:var(--ff-m);font-size:10px;letter-spacing:.12em;text-transform:uppercase;color:rgba(255,255,255,.7);padding:5px 14px;border:1px solid rgba(255,255,255,.35);border-radius:2px;display:inline-block;margin-bottom:16px}\n.legacy-svc .emerg h2{font-family:var(--ff-d);font-size:clamp(28px,4vw,50px);font-weight:800;color:#fff;line-height:1.08;margin-bottom:14px}\n.legacy-svc .emerg-sub{font-size:16px;color:rgba(255,255,255,.82);line-height:1.65;margin-bottom:30px}\n.legacy-svc .emerg-pts{display:flex;flex-direction:column;gap:12px}\n.legacy-svc .ep{display:flex;align-items:flex-start;gap:12px}\n.legacy-svc .ep-dot{width:22px;height:22px;background:rgba(0,0,0,.18);border-radius:50%;flex-shrink:0;display:flex;align-items:center;justify-content:center;font-family:var(--ff-m);font-size:9px;color:#fff;margin-top:1px}\n.legacy-svc .ep-text{font-size:14px;color:rgba(255,255,255,.85);line-height:1.55}\n.legacy-svc .ep-text strong{display:block;color:#fff;font-family:var(--ff-d);font-size:16px;font-weight:700;margin-bottom:2px}\n\n/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\n   WHY CHOOSE\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */\n.legacy-svc .why-us{padding:100px 0;background:#fff}\n.legacy-svc .wu-hd{text-align:center;max-width:580px;margin:0 auto 52px}\n\n.legacy-svc .wu-list{display:flex;flex-direction:column;gap:2px}\n.legacy-svc .wu-item{display:grid;grid-template-columns:260px 1fr;gap:32px;align-items:start;padding:28px 32px;border:1px solid var(--bdr);border-radius:4px;transition:background .2s,border-color .2s}\n.legacy-svc .wu-item:hover{background:rgba(14,110,120,.03);border-color:rgba(14,110,120,.3)}\n.legacy-svc .wu-l{display:flex;flex-direction:column;gap:6px}\n.legacy-svc .wu-tag{font-family:var(--ff-m);font-size:10px;letter-spacing:.1em;text-transform:uppercase;color:var(--signal)}\n.legacy-svc .wu-l h3{font-family:var(--ff-d);font-size:22px;font-weight:700;color:var(--text)}\n.legacy-svc .wu-item p{font-size:15px;color:var(--body);line-height:1.68;padding-top:4px}\n\n/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\n   FAQ\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */\n.legacy-svc .faq{padding:100px 0;background:var(--light)}\n.legacy-svc .faq-hd{margin-bottom:52px}\n\n.legacy-svc .faq-cols{display:grid;grid-template-columns:1fr 1fr;gap:24px;align-items:start}\n.legacy-svc .fq{background:#fff;border-radius:4px;overflow:hidden;margin-bottom:8px;border:1px solid var(--bdr)}\n.legacy-svc .fq-q{padding:18px 22px;font-family:var(--ff-d);font-size:16px;font-weight:700;color:var(--text);cursor:pointer;display:flex;justify-content:space-between;align-items:center;gap:14px;user-select:none;transition:color .18s;line-height:1.3}\n.legacy-svc .fq-q:hover{color:var(--signal)}\n.legacy-svc .fq-arr{width:20px;height:20px;flex-shrink:0;transition:transform .25s;stroke:var(--muted);fill:none;stroke-width:2;stroke-linecap:round;stroke-linejoin:round}\n.legacy-svc .fq.open .fq-arr{transform:rotate(180deg);stroke:var(--signal)}\n.legacy-svc .fq-a{max-height:0;overflow:hidden;transition:max-height .32s ease,padding .28s;font-size:13.5px;color:var(--body);line-height:1.72;padding:0 22px}\n.legacy-svc .fq.open .fq-a{max-height:180px;padding:0 22px 18px}\n\n/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\n   CTA + FORM\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */\n.legacy-svc .cta{padding:100px 0;background:var(--navy);position:relative;overflow:hidden}\n.legacy-svc .cta-bg{position:absolute;inset:0;\n  background-image:linear-gradient(rgba(14,110,120,.06) 1px,transparent 1px),\n    linear-gradient(90deg,rgba(14,110,120,.06) 1px,transparent 1px);\n  background-size:52px 52px}\n.legacy-svc .cta-in{position:relative;z-index:2;display:grid;grid-template-columns:1fr 1.15fr;gap:72px;align-items:start}\n\n.legacy-svc .cta-l h2.d{color:#fff;margin-bottom:16px}\n.legacy-svc .cta-l p{font-size:16px;color:rgba(238,246,245,.7);line-height:1.72;margin-bottom:32px}\n.legacy-svc .cta-badges{display:flex;flex-direction:column;gap:12px}\n.legacy-svc .cbadge{display:flex;align-items:center;gap:10px;font-size:14px;color:rgba(238,246,245,.75)}\n.legacy-svc .cdot{width:7px;height:7px;border-radius:50%;background:var(--signal);flex-shrink:0}\n\n/* Form */\n.legacy-svc .req-form{background:#fff;border-radius:8px;padding:36px;box-shadow:0 8px 40px rgba(4,24,28,.3)}\n.legacy-svc .form-head{font-family:var(--ff-d);font-size:22px;font-weight:700;color:var(--text);margin-bottom:6px}\n.legacy-svc .form-sub{font-size:13px;color:var(--muted);margin-bottom:28px}\n.legacy-svc .form-grid{display:grid;grid-template-columns:1fr 1fr;gap:16px;margin-bottom:16px}\n.legacy-svc .field{display:flex;flex-direction:column;gap:6px}\n.legacy-svc .field--full{grid-column:1/-1}\n.legacy-svc .field label{font-family:var(--ff-m);font-size:10px;letter-spacing:.1em;text-transform:uppercase;color:var(--muted)}\n.legacy-svc .field input, .legacy-svc .field select, .legacy-svc .field textarea{font-family:var(--ff-b);font-size:14px;color:var(--text);background:var(--light);border:1px solid var(--bdr);border-radius:var(--r);padding:11px 14px;outline:none;transition:border-color .18s,background .18s;width:100%;resize:none}\n.legacy-svc .field input:focus, .legacy-svc .field select:focus, .legacy-svc .field textarea:focus{border-color:var(--signal);background:#fff}\n.legacy-svc .field textarea{height:90px}\n\n.legacy-svc .radio-group{display:flex;gap:20px;padding:11px 0}\n.legacy-svc .radio-opt{display:flex;align-items:center;gap:8px;font-size:14px;color:var(--text);cursor:pointer}\n.legacy-svc .radio-opt input[type=radio]{accent-color:var(--signal);width:16px;height:16px;cursor:pointer}\n.legacy-svc .form-submit{width:100%;padding:16px;font-size:15px;margin-bottom:14px}\n.legacy-svc .form-note{text-align:center;font-size:12px;color:var(--muted);display:flex;align-items:center;justify-content:center;gap:8px}\n.legacy-svc .form-note::before{content:'';width:6px;height:6px;border-radius:50%;background:#22C55E;flex-shrink:0}\n\n/* в”Ђв”Ђв”Ђ RESPONSIVE в”Ђв”Ђв”Ђ */\n@media(max-width:960px){\n  .legacy-svc .w{padding:0 22px}\n  .legacy-svc .hero-wrap{grid-template-columns:1fr}\n  .legacy-svc .radar-wrap{display:none}\n  .legacy-svc .hero{padding:72px 0 64px}\n  .legacy-svc .stats-g{grid-template-columns:repeat(2,1fr)}\n  .legacy-svc .st:nth-child(2){border-right:none}\n  .legacy-svc .why-grid{grid-template-columns:1fr 1fr}\n  .legacy-svc .svc-featured{grid-template-columns:1fr}\n  .legacy-svc .svc-grid{grid-template-columns:1fr 1fr}\n  .legacy-svc .pos-grid{grid-template-columns:1fr}\n  .legacy-svc .vsl-grid{grid-template-columns:1fr}\n  .legacy-svc .emerg-in{grid-template-columns:1fr}\n  .legacy-svc .wu-item{grid-template-columns:1fr}\n  .legacy-svc .faq-cols{grid-template-columns:1fr}\n  .legacy-svc .cta-in{grid-template-columns:1fr}\n  .legacy-svc .form-grid{grid-template-columns:1fr}\n}\n@media(prefers-reduced-motion:reduce){\n  .legacy-svc .fu{opacity:1;transform:none}\n  .legacy-svc .rd-sweep{animation:none}\n  .legacy-svc .rd-blip::after{animation:none}\n}",
  "crew-change": ".legacy-svc *, .legacy-svc *::before, .legacy-svc *::after{box-sizing:border-box;margin:0;padding:0}\n\n.legacy-svc{\n  --deep:#04181c;\n  --navy:#04181c;\n  --hor:#07343a;\n  --blue:#0e6e78;\n  --signal:#f0a93b;\n  --sig-dk:#d68a1c;\n  --chart:#f6f1e8;\n  --light:#eef6f5;\n  --muted:#5f7b77;\n  --text:#0c4d56;\n  --body:#33514e;\n  --white:#FFFFFF;\n  --brass:#d68a1c;\n  --bdr:rgba(95,123,119,.22);\n  --ff-d:'Barlow Condensed',sans-serif;\n  --ff-b:'DM Sans',sans-serif;\n  --ff-m:'Space Mono',monospace;\n  --max:1200px;\n}\n\n.legacy-svc{scroll-behavior:smooth}\n.legacy-svc{font-family:var(--ff-b);background:#fff;color:var(--body);line-height:1.65;overflow-x:hidden}\n\n/* в”Ђв”Ђв”Ђ UTILITIES в”Ђв”Ђв”Ђ */\n.legacy-svc .w{max-width:var(--max);margin:0 auto;padding:0 36px}\n.legacy-svc .eb{font-family:var(--ff-m);font-size:11px;letter-spacing:.12em;text-transform:uppercase;display:block;margin-bottom:14px}\n.legacy-svc .eb-o{color:var(--signal)}\n.legacy-svc .eb-b{color:var(--brass)}\n.legacy-svc .eb-m{color:var(--muted)}\n.legacy-svc h2.d{font-family:var(--ff-d);font-weight:800;line-height:1.05;letter-spacing:-.01em;color:var(--text)}\n.legacy-svc .d-lg{font-size:clamp(28px,4vw,50px)}\n\n.legacy-svc .btn{display:inline-block;font-family:var(--ff-d);font-weight:700;font-size:14px;letter-spacing:.07em;text-transform:uppercase;padding:14px 34px;border-radius:4px;text-decoration:none;transition:all .2s;border:2px solid transparent;cursor:pointer;line-height:1}\n.legacy-svc .bto{background:var(--signal);color:#fff}.legacy-svc .bto:hover{background:var(--sig-dk)}\n.legacy-svc .btg{border-color:rgba(255,255,255,.35);color:#fff}.legacy-svc .btg:hover{border-color:#fff;background:rgba(255,255,255,.08)}\n.legacy-svc .btw{background:#fff;color:var(--sig-dk)}.legacy-svc .btw:hover{background:var(--chart)}\n\n/* в”Ђв”Ђв”Ђ SCROLL ANIMATION в”Ђв”Ђв”Ђ */\n.legacy-svc .fu{opacity:0;transform:translateY(22px);transition:opacity .6s ease,transform .6s ease}\n.legacy-svc .fu.on{opacity:1;transform:translateY(0)}\n\n/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\n   HERO\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */\n.legacy-svc .hero{position:relative;background:var(--deep);padding:108px 0 96px;overflow:hidden}\n.legacy-svc .h-grid{position:absolute;inset:0;\n  background-image:linear-gradient(rgba(14,110,120,.07) 1px,transparent 1px),\n  linear-gradient(90deg,rgba(14,110,120,.07) 1px,transparent 1px);\n  background-size:52px 52px}\n.legacy-svc .h-glow{position:absolute;inset:0;background:radial-gradient(ellipse 70% 55% at 60% 40%,rgba(14,110,120,.16) 0%,transparent 70%)}\n\n.legacy-svc .hero-in{position:relative;z-index:2;display:grid;grid-template-columns:1fr 1fr;gap:60px;align-items:center}\n.legacy-svc .hero-lede{font-family:var(--ff-m);font-size:11px;letter-spacing:.12em;text-transform:uppercase;color:var(--signal);display:block;margin-bottom:16px}\n.legacy-svc .hero-hl{font-family:var(--ff-d);font-weight:800;font-size:clamp(44px,7vw,90px);line-height:.93;color:#fff;letter-spacing:-.025em;margin-bottom:22px}\n.legacy-svc .hero-hl em{color:var(--signal);font-style:normal;display:block}\n.legacy-svc .hero-sub{font-size:17px;color:rgba(238,246,245,.72);line-height:1.72;max-width:460px;margin-bottom:38px}\n.legacy-svc .hero-acts{display:flex;gap:14px;flex-wrap:wrap}\n\n/* Route Flow Visual */\n.legacy-svc .flow-wrap{display:flex;flex-direction:column;gap:32px;align-items:center;justify-content:center}\n.legacy-svc .flow{display:flex;align-items:flex-start;width:100%;max-width:360px;gap:0}\n.legacy-svc .fn{display:flex;flex-direction:column;align-items:center;gap:10px;flex-shrink:0;z-index:1}\n.legacy-svc .fn-ico{width:58px;height:58px;border-radius:50%;background:var(--hor);border:1px solid rgba(14,110,120,.35);display:flex;align-items:center;justify-content:center;font-size:22px;position:relative}\n.legacy-svc .fn-last .fn-ico{border-color:rgba(240,169,59,.5);background:rgba(240,169,59,.1)}\n.legacy-svc .fn-lbl{font-family:var(--ff-m);font-size:9px;letter-spacing:.1em;text-transform:uppercase;color:var(--muted);white-space:nowrap}\n.legacy-svc .fc{flex:1;height:2px;background:rgba(14,110,120,.25);position:relative;overflow:hidden;margin-top:28px}\n.legacy-svc .fc::after{content:'';position:absolute;width:14px;height:8px;border-radius:50%;background:var(--signal);top:-3px;animation:fmv 2.8s cubic-bezier(.45,0,.55,1) infinite}\n.legacy-svc .fc-2::after{animation-delay:.93s}\n.legacy-svc .fc-3::after{animation-delay:1.86s}\n@keyframes fmv{from{left:-14px}to{left:100%}}\n\n.legacy-svc .flow-status{display:flex;gap:8px;flex-wrap:wrap;justify-content:center}\n.legacy-svc .fstat{font-family:var(--ff-m);font-size:9px;letter-spacing:.1em;text-transform:uppercase;padding:5px 12px;border:1px solid rgba(14,110,120,.3);border-radius:2px;color:var(--muted)}\n.legacy-svc .fstat-active{border-color:var(--signal);color:var(--signal)}\n\n/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\n   STATS\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */\n.legacy-svc .stats{background:var(--hor);border-top:1px solid rgba(14,110,120,.2);border-bottom:1px solid rgba(14,110,120,.2);padding:30px 0}\n.legacy-svc .stats-g{display:grid;grid-template-columns:repeat(4,1fr)}\n.legacy-svc .st{text-align:center;padding:14px 20px;border-right:1px solid rgba(95,123,119,.18)}\n.legacy-svc .st:last-child{border-right:none}\n.legacy-svc .stv{font-family:var(--ff-d);font-size:48px;font-weight:800;color:var(--signal);line-height:1;display:block}\n.legacy-svc .stl{font-family:var(--ff-m);font-size:10px;letter-spacing:.1em;text-transform:uppercase;color:var(--muted);margin-top:5px;display:block}\n\n/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\n   WHY IT MATTERS  (navy)\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */\n.legacy-svc .why{padding:100px 0;background:var(--navy)}\n.legacy-svc .sec-hd{text-align:center;max-width:580px;margin:0 auto 56px}\n.legacy-svc .sec-hd p{margin-top:14px;font-size:16px;line-height:1.72}\n\n.legacy-svc .why-g{display:grid;grid-template-columns:repeat(3,1fr);gap:2px}\n.legacy-svc .wc{background:rgba(255,255,255,.04);border:1px solid rgba(95,123,119,.12);padding:32px 28px;transition:background .25s}\n.legacy-svc .wc:hover{background:rgba(14,110,120,.1)}\n.legacy-svc .wc-tag{font-family:var(--ff-m);font-size:10px;letter-spacing:.12em;text-transform:uppercase;color:var(--signal);display:block;margin-bottom:10px}\n.legacy-svc .wc h3{font-family:var(--ff-d);font-size:21px;font-weight:700;color:#fff;margin-bottom:10px;border-top:2px solid var(--signal);padding-top:14px}\n.legacy-svc .wc p{font-size:13.5px;color:var(--muted);line-height:1.68}\n\n/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\n   SERVICES (chart)\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */\n.legacy-svc .services{padding:100px 0;background:var(--chart)}\n.legacy-svc .svc-hd{max-width:620px;margin-bottom:48px}\n\n/* Twin featured: Sign-On + Sign-Off */\n.legacy-svc .svc-twin{display:grid;grid-template-columns:1fr 1fr;gap:2px;margin-bottom:20px;border-radius:8px;overflow:hidden}\n.legacy-svc .stwin{background:var(--navy);padding:40px;border-top:4px solid var(--signal)}\n.legacy-svc .stwin .etag{font-family:var(--ff-m);font-size:10px;letter-spacing:.12em;text-transform:uppercase;color:var(--signal);padding:4px 12px;border:1px solid rgba(240,169,59,.4);border-radius:2px;display:inline-block;margin-bottom:18px}\n.legacy-svc .stwin h3{font-family:var(--ff-d);font-size:27px;font-weight:800;color:#fff;margin-bottom:12px}\n.legacy-svc .stwin p{font-size:14px;color:rgba(238,246,245,.68);line-height:1.7;margin-bottom:22px}\n.legacy-svc .stwin-chips{display:flex;flex-direction:column;gap:9px}\n.legacy-svc .sch{display:flex;align-items:center;gap:10px;font-size:13px;color:rgba(238,246,245,.78)}\n.legacy-svc .scdot{width:5px;height:5px;border-radius:50%;background:var(--signal);flex-shrink:0}\n\n/* Other 8 services */\n.legacy-svc .svc-g{display:grid;grid-template-columns:repeat(4,1fr);gap:14px}\n.legacy-svc .sc{background:#fff;border-radius:6px;padding:24px;border-left:3px solid var(--bdr);box-shadow:0 2px 10px rgba(4,24,28,.05);transition:border-color .2s,transform .22s,box-shadow .2s}\n.legacy-svc .sc:hover{border-left-color:var(--signal);transform:translateY(-3px);box-shadow:0 8px 22px rgba(4,24,28,.09)}\n.legacy-svc .sc h3{font-family:var(--ff-d);font-size:17px;font-weight:700;color:var(--text);margin-bottom:7px}\n.legacy-svc .sc p{font-size:13px;color:var(--body);line-height:1.63}\n\n/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\n   PROCESS (white, numbered cards)\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */\n.legacy-svc .process{padding:100px 0;background:#fff}\n.legacy-svc .proc-hd{text-align:center;max-width:560px;margin:0 auto 56px}\n\n.legacy-svc .proc-g{display:grid;grid-template-columns:1fr 1fr;gap:16px}\n.legacy-svc .step{display:flex;gap:20px;padding:28px 30px;border:1px solid var(--bdr);border-radius:6px;transition:border-color .22s,background .22s}\n.legacy-svc .step:hover{border-color:var(--signal);background:rgba(240,169,59,.03)}\n.legacy-svc .step-n{font-family:var(--ff-d);font-size:64px;font-weight:800;color:rgba(240,169,59,.18);line-height:.88;flex-shrink:0;width:52px;transition:color .22s}\n.legacy-svc .step:hover .step-n{color:var(--signal)}\n.legacy-svc .step h3{font-family:var(--ff-d);font-size:19px;font-weight:700;color:var(--text);margin-bottom:8px}\n.legacy-svc .step p{font-size:13px;color:var(--body);line-height:1.65}\n\n/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\n   VESSEL TYPES (deep)\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */\n.legacy-svc .vessels{padding:100px 0;background:var(--deep)}\n.legacy-svc .vsl-hd{max-width:580px;margin-bottom:52px}\n.legacy-svc .vsl-hd h2.d{color:#fff}\n.legacy-svc .vsl-hd p{margin-top:14px;font-size:15px;color:var(--muted);line-height:1.65}\n\n.legacy-svc .vsl-g{display:grid;grid-template-columns:1fr 1fr;gap:2px}\n.legacy-svc .vt{display:flex;align-items:flex-start;gap:18px;padding:22px 26px;background:rgba(255,255,255,.04);border:1px solid rgba(95,123,119,.1);transition:background .25s}\n.legacy-svc .vt:hover{background:rgba(14,110,120,.1)}\n.legacy-svc .vt-i{font-size:26px;flex-shrink:0;line-height:1;margin-top:2px}\n.legacy-svc .vt h3{font-family:var(--ff-d);font-size:17px;font-weight:700;color:#fff;margin-bottom:6px}\n.legacy-svc .vt p{font-size:12.5px;color:var(--muted);line-height:1.6}\n\n/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\n   POSITIONS (chart)\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */\n.legacy-svc .positions{padding:100px 0;background:var(--chart)}\n.legacy-svc .pos-hd{text-align:center;max-width:560px;margin:0 auto 52px}\n\n.legacy-svc .pos-g{display:grid;grid-template-columns:repeat(3,1fr);gap:24px}\n.legacy-svc .dept{background:#fff;border-radius:8px;overflow:hidden;box-shadow:0 2px 14px rgba(4,24,28,.07);border:1px solid var(--bdr)}\n.legacy-svc .dept-h{padding:22px 26px;background:var(--navy);display:flex;align-items:center;gap:14px}\n.legacy-svc .dept-h h3{font-family:var(--ff-d);font-size:21px;font-weight:700;color:#fff}\n.legacy-svc .dept-ico{width:40px;height:40px;background:rgba(240,169,59,.2);border-radius:6px;display:flex;align-items:center;justify-content:center;font-size:20px;flex-shrink:0}\n.legacy-svc .dept-body{padding:18px 26px 22px}\n.legacy-svc .role{padding:10px 0;border-bottom:1px solid var(--light);font-size:14px;color:var(--body);display:flex;align-items:flex-start;gap:9px}\n.legacy-svc .role:last-child{border-bottom:none}\n.legacy-svc .role::before{content:'';width:5px;height:5px;border-radius:50%;background:var(--signal);flex-shrink:0;margin-top:7px}\n\n/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\n   COMPLIANCE BADGES (light)\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */\n.legacy-svc .comp{padding:100px 0;background:var(--light)}\n.legacy-svc .comp-hd{text-align:center;max-width:560px;margin:0 auto 52px}\n\n.legacy-svc .comp-g{display:grid;grid-template-columns:repeat(3,1fr);gap:18px}\n.legacy-svc .cbadge{background:#fff;border:1px solid var(--bdr);border-radius:8px;padding:28px 24px;text-align:center;transition:border-color .2s,box-shadow .2s,transform .22s}\n.legacy-svc .cbadge:hover{border-color:var(--signal);box-shadow:0 6px 20px rgba(240,169,59,.12);transform:translateY(-3px)}\n.legacy-svc .cbadge-ico{font-size:30px;display:block;margin-bottom:14px}\n.legacy-svc .cbadge-name{font-family:var(--ff-d);font-size:18px;font-weight:700;color:var(--text);margin-bottom:8px;display:block}\n.legacy-svc .cbadge p{font-size:12.5px;color:var(--muted);line-height:1.65}\n\n/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\n   EMERGENCY STRIP (orange)\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */\n.legacy-svc .emerg{padding:84px 0;background:linear-gradient(135deg,var(--sig-dk) 0%,var(--signal) 100%)}\n.legacy-svc .emerg-in{display:grid;grid-template-columns:1fr 1fr;gap:64px;align-items:start}\n.legacy-svc .emerg-b{font-family:var(--ff-m);font-size:10px;letter-spacing:.12em;text-transform:uppercase;color:rgba(255,255,255,.7);padding:5px 14px;border:1px solid rgba(255,255,255,.35);border-radius:2px;display:inline-block;margin-bottom:16px}\n.legacy-svc .emerg h2{font-family:var(--ff-d);font-size:clamp(28px,4vw,50px);font-weight:800;color:#fff;line-height:1.08;margin-bottom:14px}\n.legacy-svc .emerg-sub{font-size:15px;color:rgba(255,255,255,.82);line-height:1.65;margin-bottom:28px}\n.legacy-svc .emerg-list{display:flex;flex-direction:column;gap:12px}\n.legacy-svc .el{display:flex;align-items:flex-start;gap:12px}\n.legacy-svc .el-n{width:22px;height:22px;background:rgba(0,0,0,.18);border-radius:50%;display:flex;align-items:center;justify-content:center;font-family:var(--ff-m);font-size:9px;color:#fff;flex-shrink:0;margin-top:1px}\n.legacy-svc .el-t{font-size:14px;color:rgba(255,255,255,.85);line-height:1.55}\n.legacy-svc .el-t strong{display:block;color:#fff;font-family:var(--ff-d);font-size:16px;font-weight:700;margin-bottom:2px}\n\n/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\n   WHY US (white)\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */\n.legacy-svc .why-us{padding:100px 0;background:#fff}\n.legacy-svc .wu-hd{text-align:center;max-width:560px;margin:0 auto 48px}\n\n.legacy-svc .wu-list{display:flex;flex-direction:column;gap:2px}\n.legacy-svc .wu{display:grid;grid-template-columns:240px 1fr;gap:32px;align-items:start;padding:26px 30px;border:1px solid var(--bdr);border-radius:4px;transition:background .2s,border-color .2s}\n.legacy-svc .wu:hover{background:rgba(14,110,120,.03);border-color:rgba(14,110,120,.3)}\n.legacy-svc .wu-l{display:flex;flex-direction:column;gap:5px}\n.legacy-svc .wu-tag{font-family:var(--ff-m);font-size:10px;letter-spacing:.1em;text-transform:uppercase;color:var(--signal)}\n.legacy-svc .wu-l h3{font-family:var(--ff-d);font-size:22px;font-weight:700;color:var(--text)}\n.legacy-svc .wu p{font-size:15px;color:var(--body);line-height:1.68;padding-top:4px}\n\n/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\n   BENEFITS + INDUSTRIES (chart)\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */\n.legacy-svc .ben-ind{padding:100px 0;background:var(--chart)}\n.legacy-svc .bi-grid{display:grid;grid-template-columns:1fr 1fr;gap:80px;align-items:start}\n\n.legacy-svc .ben-list{list-style:none;display:flex;flex-direction:column;gap:16px;margin-top:36px}\n.legacy-svc .ben-item{display:flex;gap:14px;align-items:flex-start}\n.legacy-svc .ben-ck{width:24px;height:24px;background:var(--signal);border-radius:4px;flex-shrink:0;display:flex;align-items:center;justify-content:center;margin-top:1px}\n.legacy-svc .ben-ck svg{width:13px;height:13px;stroke:#fff;fill:none;stroke-width:2.5;stroke-linecap:round;stroke-linejoin:round}\n.legacy-svc .ben-item span{font-size:15px;color:var(--body);line-height:1.65}\n\n.legacy-svc .ind-g{display:grid;grid-template-columns:1fr 1fr;gap:14px;margin-top:36px}\n.legacy-svc .ind-c{padding:24px;border:1px solid var(--bdr);border-radius:6px;transition:border-color .2s,box-shadow .2s;background:#fff}\n.legacy-svc .ind-c:hover{border-color:var(--signal);box-shadow:0 4px 16px rgba(240,169,59,.1)}\n.legacy-svc .ind-i{font-size:26px;display:block;margin-bottom:12px}\n.legacy-svc .ind-c h4{font-family:var(--ff-d);font-size:17px;font-weight:700;color:var(--text);margin-bottom:7px}\n.legacy-svc .ind-c p{font-size:13px;color:var(--muted);line-height:1.6}\n\n/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\n   FAQ (light)\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */\n.legacy-svc .faq{padding:100px 0;background:var(--light)}\n.legacy-svc .faq-hd{margin-bottom:52px}\n\n.legacy-svc .faq-cols{display:grid;grid-template-columns:1fr 1fr;gap:24px;align-items:start}\n.legacy-svc .fq{background:#fff;border-radius:4px;overflow:hidden;margin-bottom:8px;border:1px solid var(--bdr)}\n.legacy-svc .fq-q{padding:18px 20px;font-family:var(--ff-d);font-size:16px;font-weight:700;color:var(--text);cursor:pointer;display:flex;justify-content:space-between;align-items:center;gap:12px;user-select:none;transition:color .18s;line-height:1.3}\n.legacy-svc .fq-q:hover{color:var(--signal)}\n.legacy-svc .fq-arr{width:18px;height:18px;flex-shrink:0;transition:transform .25s;stroke:var(--muted);fill:none;stroke-width:2;stroke-linecap:round;stroke-linejoin:round}\n.legacy-svc .fq.open .fq-arr{transform:rotate(180deg);stroke:var(--signal)}\n.legacy-svc .fq-a{max-height:0;overflow:hidden;transition:max-height .32s ease,padding .28s;font-size:13.5px;color:var(--body);line-height:1.7;padding:0 20px}\n.legacy-svc .fq.open .fq-a{max-height:180px;padding:0 20px 18px}\n\n/* в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ\n   CTA + FORM (navy)\nв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ */\n.legacy-svc .cta{padding:100px 0;background:var(--navy);position:relative;overflow:hidden}\n.legacy-svc .cta-bg{position:absolute;inset:0;\n  background-image:linear-gradient(rgba(14,110,120,.06) 1px,transparent 1px),\n  linear-gradient(90deg,rgba(14,110,120,.06) 1px,transparent 1px);\n  background-size:52px 52px}\n.legacy-svc .cta-in{position:relative;z-index:2;display:grid;grid-template-columns:1fr 1.15fr;gap:72px;align-items:start}\n\n.legacy-svc .cta-l h2.d{color:#fff;margin-bottom:16px}\n.legacy-svc .cta-l p{font-size:15.5px;color:rgba(238,246,245,.7);line-height:1.72;margin-bottom:32px}\n.legacy-svc .cta-pts{display:flex;flex-direction:column;gap:12px}\n.legacy-svc .cpt{display:flex;align-items:center;gap:10px;font-size:14px;color:rgba(238,246,245,.75)}\n.legacy-svc .cdot{width:7px;height:7px;border-radius:50%;background:var(--signal);flex-shrink:0}\n\n/* Form Card */\n.legacy-svc .req-form{background:#fff;border-radius:8px;padding:36px;box-shadow:0 8px 40px rgba(4,24,28,.3)}\n.legacy-svc .form-head{font-family:var(--ff-d);font-size:22px;font-weight:700;color:var(--text);margin-bottom:4px}\n.legacy-svc .form-sub{font-size:13px;color:var(--muted);margin-bottom:28px}\n.legacy-svc .form-g{display:grid;grid-template-columns:1fr 1fr;gap:14px;margin-bottom:14px}\n.legacy-svc .field{display:flex;flex-direction:column;gap:6px}\n.legacy-svc .field--full{grid-column:1/-1}\n.legacy-svc .field label{font-family:var(--ff-m);font-size:10px;letter-spacing:.1em;text-transform:uppercase;color:var(--muted)}\n.legacy-svc .field input, .legacy-svc .field select, .legacy-svc .field textarea{font-family:var(--ff-b);font-size:14px;color:var(--text);background:var(--light);border:1px solid var(--bdr);border-radius:4px;padding:11px 14px;outline:none;transition:border-color .18s,background .18s;width:100%}\n.legacy-svc .field input:focus, .legacy-svc .field select:focus, .legacy-svc .field textarea:focus{border-color:var(--signal);background:#fff}\n.legacy-svc .field textarea{height:88px;resize:none}\n.legacy-svc .rg{display:flex;gap:20px;padding:11px 0}\n.legacy-svc .ro{display:flex;align-items:center;gap:8px;font-size:14px;color:var(--text);cursor:pointer}\n.legacy-svc .ro input[type=radio]{accent-color:var(--signal);width:16px;height:16px;cursor:pointer}\n.legacy-svc .fsub{width:100%;padding:16px;font-size:15px;margin-bottom:12px}\n.legacy-svc .fnote{text-align:center;font-size:12px;color:var(--muted);display:flex;align-items:center;justify-content:center;gap:8px}\n.legacy-svc .fnote::before{content:'';width:6px;height:6px;border-radius:50%;background:#22C55E;flex-shrink:0}\n\n/* в”Ђв”Ђв”Ђ RESPONSIVE в”Ђв”Ђв”Ђ */\n@media(max-width:980px){\n  .legacy-svc .w{padding:0 22px}\n  .legacy-svc .hero-in{grid-template-columns:1fr}\n  .legacy-svc .flow-wrap{display:none}\n  .legacy-svc .hero{padding:72px 0 64px}\n  .legacy-svc .stats-g{grid-template-columns:1fr 1fr}\n  .legacy-svc .st:nth-child(2){border-right:none}\n  .legacy-svc .why-g{grid-template-columns:1fr 1fr}\n  .legacy-svc .svc-twin{grid-template-columns:1fr}\n  .legacy-svc .svc-g{grid-template-columns:1fr 1fr}\n  .legacy-svc .proc-g{grid-template-columns:1fr}\n  .legacy-svc .vsl-g{grid-template-columns:1fr}\n  .legacy-svc .pos-g{grid-template-columns:1fr}\n  .legacy-svc .comp-g{grid-template-columns:1fr 1fr}\n  .legacy-svc .emerg-in{grid-template-columns:1fr}\n  .legacy-svc .wu{grid-template-columns:1fr}\n  .legacy-svc .bi-grid{grid-template-columns:1fr;gap:48px}\n  .legacy-svc .faq-cols{grid-template-columns:1fr}\n  .legacy-svc .cta-in{grid-template-columns:1fr}\n  .legacy-svc .form-g{grid-template-columns:1fr}\n}\n@media(prefers-reduced-motion:reduce){\n  .legacy-svc .fu{opacity:1;transform:none}\n  .legacy-svc .fc::after{animation:none}\n}",
  "offshore-manning": "/* в”Ђв”Ђ Reset в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n.legacy-svc *, .legacy-svc *::before, .legacy-svc *::after{box-sizing:border-box;margin:0;padding:0}\n.legacy-svc{scroll-behavior:smooth}\n.legacy-svc ul, .legacy-svc ol{list-style:none}\n.legacy-svc a{text-decoration:none}\n.legacy-svc button{font-family:inherit;cursor:pointer}\n\n/* в”Ђв”Ђ Design Tokens в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n.legacy-svc{\n  --navy:    #07343a;\n  --navy-m:  #0c4d56;\n  --navy-l:  #0c5760;\n  --navy-xd: #04181c;\n  --orange:  #f0a93b;\n  --orange-d:#d68a1c;\n  --amber:   #f6b53f;\n  --steel:   #eef6f5;\n  --white:   #FFFFFF;\n  --text:    #0b2a2e;\n  --text-m:  #33514e;\n  --text-l:  #5f7b77;\n  --border:  #d8e7e3;\n  --fd:'Barlow Condensed',sans-serif;\n  --fb:'Inter',sans-serif;\n  --xl:100px;\n}\n\n.legacy-svc{font-family:var(--fb);color:var(--text);background:var(--white);font-size:16px;line-height:1.6;-webkit-font-smoothing:antialiased}\n\n/* в”Ђв”Ђ Utilities в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n.legacy-svc .wrap{max-width:1160px;margin:0 auto;padding:0 24px}\n\n.legacy-svc .eyebrow{font-size:11px;font-weight:600;letter-spacing:.14em;text-transform:uppercase;color:var(--orange);display:block;margin-bottom:14px}\n.legacy-svc .eyebrow-amber{color:var(--amber)}\n.legacy-svc .eyebrow-steel{color:rgba(255,255,255,.45)}\n\n.legacy-svc .hdisplay{font-family:var(--fd);font-weight:800;font-size:clamp(2rem,4.5vw,3.2rem);line-height:1.02;text-transform:uppercase;letter-spacing:-.01em;color:var(--text)}\n.legacy-svc .hdisplay-white{color:var(--white)}\n\n.legacy-svc .subtext{font-size:16px;line-height:1.68;color:var(--text-m);max-width:640px}\n.legacy-svc .subtext-light{color:rgba(255,255,255,.65)}\n\n/* Compass-diamond divider */\n.legacy-svc .cdiv{display:flex;align-items:center;gap:10px;margin-bottom:36px}\n.legacy-svc .cdiv::before, .legacy-svc .cdiv::after{content:'';width:44px;height:1.5px;background:var(--orange)}\n.legacy-svc .cdiv-gem{width:7px;height:7px;background:var(--orange);transform:rotate(45deg);flex-shrink:0}\n.legacy-svc .s-ctr{text-align:center}\n.legacy-svc .s-ctr .cdiv{margin-left:auto;margin-right:auto;width:fit-content}\n.legacy-svc .s-ctr .subtext{margin:16px auto 0}\n\n/* Buttons */\n.legacy-svc .btn{display:inline-flex;align-items:center;gap:7px;padding:14px 28px;border-radius:3px;font-family:var(--fb);font-weight:600;font-size:14.5px;border:none;transition:all .2s;line-height:1}\n.legacy-svc .btn-solid{background:var(--orange);color:#fff}\n.legacy-svc .btn-solid:hover{background:var(--orange-d);transform:translateY(-1px)}\n.legacy-svc .btn-ghost{background:transparent;color:#fff;border:1.5px solid rgba(255,255,255,.34)}\n.legacy-svc .btn-ghost:hover{border-color:#fff;background:rgba(255,255,255,.07)}\n\n/* Bullet list (shared across dark sections) */\n.legacy-svc .bul-list li{display:flex;align-items:flex-start;gap:10px;padding:9px 0;border-bottom:1px solid rgba(255,255,255,.06);font-size:14px;color:rgba(255,255,255,.73)}\n.legacy-svc .bul-list li:last-child{border-bottom:none}\n.legacy-svc .bul-list li::before{content:'в–ё';color:var(--orange);flex-shrink:0;font-size:11px;margin-top:3px}\n\n/* в”Ђв”Ђ HERO в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n.legacy-svc .hero{\n  background-color:var(--navy);\n  background-image:\n    radial-gradient(ellipse 65% 90% at 90% 50%,rgba(14,110,120,.60) 0%,transparent 65%),\n    radial-gradient(ellipse 40% 40% at 8% 88%,rgba(240,169,59,.06) 0%,transparent 55%);\n  padding:96px 0 82px;\n}\n\n.legacy-svc .hero-badge{display:inline-flex;align-items:center;gap:8px;background:rgba(240,169,59,.13);border:1px solid rgba(240,169,59,.28);border-radius:2px;padding:7px 14px;font-size:11px;font-weight:600;letter-spacing:.1em;text-transform:uppercase;color:var(--amber);margin-bottom:22px}\n\n.legacy-svc .hero-title{font-family:var(--fd);font-size:clamp(3.8rem,10.5vw,8rem);font-weight:800;text-transform:uppercase;line-height:.90;letter-spacing:-.02em;color:#fff;margin-bottom:28px}\n.legacy-svc .hero-title .hl{color:var(--orange);display:block}\n\n.legacy-svc .hero-desc{font-size:16.5px;line-height:1.65;color:rgba(255,255,255,.70);max-width:540px;margin-bottom:38px}\n.legacy-svc .hero-btns{display:flex;gap:12px;flex-wrap:wrap;margin-bottom:56px}\n\n.legacy-svc .cert-strip{display:flex;align-items:center;gap:20px;flex-wrap:wrap}\n.legacy-svc .cert-label{font-size:10.5px;font-weight:600;letter-spacing:.12em;text-transform:uppercase;color:rgba(255,255,255,.32)}\n.legacy-svc .cert-badges{display:flex;align-items:center;gap:7px;flex-wrap:wrap}\n.legacy-svc .cert-badge{padding:5px 11px;border:1px solid rgba(255,255,255,.16);border-radius:2px;font-size:10.5px;font-weight:600;letter-spacing:.07em;color:rgba(255,255,255,.60)}\n\n/* в”Ђв”Ђ STATS BAR в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n.legacy-svc .stats-bar{background:var(--orange);padding:22px 0}\n.legacy-svc .stats-inner{display:grid;grid-template-columns:repeat(4,1fr)}\n.legacy-svc .stat-item{text-align:center;padding:6px 12px;border-right:1px solid rgba(255,255,255,.22)}\n.legacy-svc .stat-item:last-child{border-right:none}\n.legacy-svc .stat-n{font-family:var(--fd);font-size:2.1rem;font-weight:800;color:#fff;line-height:1}\n.legacy-svc .stat-l{font-size:10.5px;font-weight:600;color:rgba(255,255,255,.86);text-transform:uppercase;letter-spacing:.07em;margin-top:4px}\n\n/* в”Ђв”Ђ WHY SPECIALIZED в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n.legacy-svc .sec-why-spec{padding:var(--xl) 0;background:var(--white)}\n\n.legacy-svc .why-spec-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:20px;margin-top:48px}\n\n.legacy-svc .wsc{padding:24px;border:1.5px solid var(--border);border-radius:5px;transition:all .2s}\n.legacy-svc .wsc:hover{border-color:var(--orange);box-shadow:0 4px 18px rgba(240,169,59,.07)}\n\n.legacy-svc .wsc-icon{width:40px;height:40px;background:rgba(240,169,59,.09);border-radius:5px;display:flex;align-items:center;justify-content:center;color:var(--orange);margin-bottom:14px}\n\n.legacy-svc .wsc-title{font-size:14.5px;font-weight:700;color:var(--text);margin-bottom:8px}\n.legacy-svc .wsc-desc{font-size:13px;color:var(--text-m);line-height:1.55}\n\n/* в”Ђв”Ђ SERVICES в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n.legacy-svc .sec-services{padding:var(--xl) 0;background:var(--navy)}\n.legacy-svc .sec-services .subtext{color:rgba(255,255,255,.62)}\n\n.legacy-svc .svc-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:1px;background:rgba(255,255,255,.06);border:1px solid rgba(255,255,255,.06);border-radius:6px;overflow:hidden;margin-top:48px}\n.legacy-svc .svc-card{background:var(--navy-m);padding:28px 22px;transition:background .2s}\n.legacy-svc .svc-card:hover{background:var(--navy-l)}\n.legacy-svc .svc-ico{width:33px;height:33px;color:var(--orange);margin-bottom:14px}\n.legacy-svc .svc-title{font-family:var(--fd);font-size:1.12rem;font-weight:700;text-transform:uppercase;letter-spacing:.03em;color:#fff;margin-bottom:8px}\n.legacy-svc .svc-desc{font-size:13px;color:rgba(255,255,255,.56);line-height:1.54}\n\n/* в”Ђв”Ђ VESSEL TYPES в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n.legacy-svc .sec-vessels{padding:var(--xl) 0;background:var(--steel)}\n\n.legacy-svc .vess-grid{display:grid;grid-template-columns:repeat(5,1fr);gap:14px;margin-top:48px}\n.legacy-svc .vess-card{background:var(--white);border:1.5px solid var(--border);border-radius:5px;padding:20px 14px;text-align:center;transition:all .2s;cursor:default}\n.legacy-svc .vess-card:hover{border-color:var(--orange);box-shadow:0 4px 18px rgba(240,169,59,.10);transform:translateY(-2px)}\n.legacy-svc .vess-ico{font-size:1.85rem;margin-bottom:10px;display:block}\n.legacy-svc .vess-name{font-family:var(--fd);font-size:.95rem;font-weight:700;text-transform:uppercase;letter-spacing:.04em;color:var(--text);margin-bottom:6px}\n.legacy-svc .vess-desc{font-size:11.5px;color:var(--text-l);line-height:1.5}\n\n/* в”Ђв”Ђ POSITIONS в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n.legacy-svc .sec-pos{padding:var(--xl) 0;background:var(--white)}\n\n.legacy-svc .pos-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:32px;margin-top:48px}\n.legacy-svc .pos-dept{border-top:3px solid var(--orange);padding-top:24px}\n.legacy-svc .dept-hd{font-family:var(--fd);font-size:1.05rem;font-weight:700;text-transform:uppercase;letter-spacing:.07em;color:var(--text);margin-bottom:18px;display:flex;align-items:center;gap:9px}\n.legacy-svc .dept-hd svg{width:19px;height:19px;color:var(--orange);flex-shrink:0}\n.legacy-svc .pos-list li{padding:12px 0;border-bottom:1px solid var(--border)}\n.legacy-svc .pos-list li:last-child{border-bottom:none}\n.legacy-svc .pos-rank{font-size:13.5px;font-weight:600;color:var(--text);margin-bottom:3px}\n.legacy-svc .pos-desc{font-size:12px;color:var(--text-m);line-height:1.45}\n\n/* в”Ђв”Ђ PROCESS в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n.legacy-svc .sec-process{padding:var(--xl) 0;background:var(--navy)}\n.legacy-svc .sec-process .subtext{color:rgba(255,255,255,.62)}\n\n.legacy-svc .proc-grid{display:grid;grid-template-columns:1fr 1fr;gap:14px;margin-top:48px}\n.legacy-svc .proc-item{display:flex;align-items:flex-start;gap:16px;padding:20px 22px;background:rgba(255,255,255,.04);border:1px solid rgba(255,255,255,.07);border-radius:5px;transition:background .2s}\n.legacy-svc .proc-item:hover{background:rgba(255,255,255,.065)}\n.legacy-svc .proc-num{font-family:var(--fd);font-size:2.3rem;font-weight:800;color:rgba(240,169,59,.26);line-height:1;flex-shrink:0;width:48px}\n.legacy-svc .proc-title{font-size:13px;font-weight:700;text-transform:uppercase;letter-spacing:.05em;color:#fff;margin-bottom:4px}\n.legacy-svc .proc-desc{font-size:12.5px;color:rgba(255,255,255,.52);line-height:1.5}\n\n/* в”Ђв”Ђ SAFETY & COMPLIANCE (SIGNATURE ELEMENT) в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n/* Dark cert authority cards on light background вЂ” \n   large white abbreviations give instant visual authority */\n.legacy-svc .sec-certs{padding:var(--xl) 0;background:var(--steel)}\n\n.legacy-svc .cert-cards-grid{display:grid;grid-template-columns:repeat(5,1fr);gap:14px;margin-top:48px}\n\n.legacy-svc .cert-card{background:var(--navy);border-radius:5px;padding:22px 16px;text-align:center;border-bottom:3px solid var(--orange);transition:transform .2s;cursor:default}\n.legacy-svc .cert-card:hover{transform:translateY(-2px)}\n\n.legacy-svc .cert-abbr{font-family:var(--fd);font-size:1.65rem;font-weight:800;color:#fff;margin-bottom:5px;letter-spacing:.02em;line-height:1.1}\n.legacy-svc .cert-full{font-size:10px;font-weight:600;letter-spacing:.06em;color:var(--amber);text-transform:uppercase;margin-bottom:8px;display:block}\n.legacy-svc .cert-desc{font-size:11.5px;color:rgba(255,255,255,.52);line-height:1.5}\n\n/* в”Ђв”Ђ EMERGENCY в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n.legacy-svc .sec-emg{padding:var(--xl) 0;background:var(--navy-xd);border-top:3px solid var(--orange)}\n\n.legacy-svc .emg-inner{display:grid;grid-template-columns:1fr 1fr;gap:72px;align-items:start}\n.legacy-svc .emg-tagline{font-family:var(--fd);font-size:1.65rem;font-weight:700;text-transform:uppercase;color:var(--orange);margin:22px 0 26px;letter-spacing:.04em}\n.legacy-svc .emg-sublabel{font-size:10px;font-weight:700;letter-spacing:.13em;text-transform:uppercase;color:rgba(255,255,255,.32);margin-bottom:10px;display:block}\n.legacy-svc .res-box{background:rgba(240,169,59,.07);border:1px solid rgba(240,169,59,.22);border-radius:5px;padding:26px}\n.legacy-svc .res-title{font-family:var(--fd);font-size:1.05rem;font-weight:700;text-transform:uppercase;letter-spacing:.07em;color:var(--amber);margin-bottom:18px}\n.legacy-svc .emg-note{margin-top:20px;font-size:13px;color:rgba(255,255,255,.38);line-height:1.6}\n\n/* в”Ђв”Ђ WHY CHOOSE в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n.legacy-svc .sec-choose{padding:var(--xl) 0;background:var(--white)}\n\n.legacy-svc .ch-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:18px;margin-top:48px}\n.legacy-svc .ch-card{padding:22px;border:1.5px solid var(--border);border-radius:5px;transition:all .2s}\n.legacy-svc .ch-card:hover{border-color:var(--orange);box-shadow:0 4px 18px rgba(240,169,59,.07)}\n.legacy-svc .ch-icon{width:36px;height:36px;background:rgba(240,169,59,.08);border-radius:5px;display:flex;align-items:center;justify-content:center;color:var(--orange);margin-bottom:14px}\n.legacy-svc .ch-title{font-size:14px;font-weight:700;color:var(--text);margin-bottom:6px}\n.legacy-svc .ch-desc{font-size:12.5px;color:var(--text-m);line-height:1.54}\n\n/* в”Ђв”Ђ BENEFITS в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n.legacy-svc .sec-benefits{padding:var(--xl) 0;background:var(--steel)}\n\n.legacy-svc .ben-grid{display:grid;grid-template-columns:1fr 1fr;gap:18px;margin-top:48px}\n.legacy-svc .ben-item{display:flex;gap:16px;padding:22px;background:var(--white);border:1.5px solid var(--border);border-radius:5px;align-items:flex-start;transition:border-color .2s}\n.legacy-svc .ben-item:hover{border-color:var(--orange)}\n.legacy-svc .ben-ico{width:36px;height:36px;background:rgba(240,169,59,.08);border-radius:5px;display:flex;align-items:center;justify-content:center;color:var(--orange);flex-shrink:0;margin-top:2px}\n.legacy-svc .ben-title{font-size:14.5px;font-weight:700;color:var(--text);margin-bottom:5px}\n.legacy-svc .ben-desc{font-size:13px;color:var(--text-m);line-height:1.5}\n\n/* в”Ђв”Ђ INDUSTRIES (dark treatment) в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n.legacy-svc .sec-industries{padding:var(--xl) 0;background:var(--navy)}\n.legacy-svc .sec-industries .subtext{color:rgba(255,255,255,.62)}\n\n.legacy-svc .ind-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:14px;margin-top:48px}\n\n.legacy-svc .ind-card{background:rgba(255,255,255,.04);border:1px solid rgba(255,255,255,.08);border-top:2px solid var(--orange);border-radius:5px;padding:24px 20px;transition:background .2s}\n.legacy-svc .ind-card:hover{background:rgba(255,255,255,.07)}\n.legacy-svc .ind-ico{font-size:1.6rem;margin-bottom:12px;display:block}\n.legacy-svc .ind-title{font-family:var(--fd);font-size:1.1rem;font-weight:700;text-transform:uppercase;letter-spacing:.04em;color:#fff;margin-bottom:8px}\n.legacy-svc .ind-desc{font-size:13px;color:rgba(255,255,255,.57);line-height:1.55}\n\n/* в”Ђв”Ђ FAQ в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n.legacy-svc .sec-faq{padding:var(--xl) 0;background:var(--steel)}\n\n.legacy-svc .faq-list{max-width:780px;margin:48px auto 0}\n.legacy-svc .faq-item{border-bottom:1px solid var(--border)}\n.legacy-svc .faq-item:first-child{border-top:1px solid var(--border)}\n.legacy-svc .faq-btn{width:100%;background:none;border:none;display:flex;align-items:center;justify-content:space-between;gap:16px;padding:19px 0;text-align:left;font-family:var(--fb);font-size:14.5px;font-weight:600;color:var(--text);transition:color .2s}\n.legacy-svc .faq-btn:hover, .legacy-svc .faq-btn.open{color:var(--orange)}\n.legacy-svc .faq-ico{width:17px;height:17px;flex-shrink:0;color:var(--orange);transition:transform .25s ease}\n.legacy-svc .faq-btn.open .faq-ico{transform:rotate(45deg)}\n.legacy-svc .faq-body{overflow:hidden;max-height:0;transition:max-height .32s ease}\n.legacy-svc .faq-body.open{max-height:500px}\n.legacy-svc .faq-ans{font-size:13.5px;color:var(--text-m);line-height:1.66;padding-bottom:18px;padding-right:32px}\n\n/* в”Ђв”Ђ CTA в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n.legacy-svc .sec-cta{padding:var(--xl) 0;background:var(--navy);position:relative;overflow:hidden}\n.legacy-svc .sec-cta::before{content:'';position:absolute;top:-60px;right:-60px;width:360px;height:360px;background:radial-gradient(circle,rgba(240,169,59,.09) 0%,transparent 68%);pointer-events:none}\n\n.legacy-svc .cta-grid{display:grid;grid-template-columns:1fr 1fr;gap:72px;align-items:start;position:relative;z-index:1}\n.legacy-svc .cta-left .hdisplay{color:#fff;margin-bottom:14px}\n.legacy-svc .cta-left p{font-size:14.5px;color:rgba(255,255,255,.62);line-height:1.65;margin-bottom:18px}\n\n.legacy-svc .fw{display:grid;gap:13px}\n.legacy-svc .frow{display:grid;grid-template-columns:1fr 1fr;gap:13px}\n.legacy-svc .fg label{display:block;font-size:11px;font-weight:600;letter-spacing:.09em;text-transform:uppercase;color:rgba(255,255,255,.42);margin-bottom:6px}\n.legacy-svc .fg input, .legacy-svc .fg select, .legacy-svc .fg textarea{width:100%;background:rgba(255,255,255,.06);border:1px solid rgba(255,255,255,.14);border-radius:3px;padding:11px 13px;font-family:var(--fb);font-size:14px;color:#fff;outline:none;transition:border-color .2s;-webkit-appearance:none}\n.legacy-svc .fg input::placeholder, .legacy-svc .fg textarea::placeholder{color:rgba(255,255,255,.22)}\n.legacy-svc .fg input:focus, .legacy-svc .fg select:focus, .legacy-svc .fg textarea:focus{border-color:rgba(240,169,59,.60)}\n.legacy-svc .fg select option{background:var(--navy-m);color:#fff}\n.legacy-svc .fg textarea{resize:vertical;min-height:76px}\n.legacy-svc .form-btn{width:100%;background:var(--orange);color:#fff;border:none;border-radius:3px;padding:14px;font-family:var(--fb);font-size:14.5px;font-weight:600;transition:background .2s}\n.legacy-svc .form-btn:hover{background:var(--orange-d)}\n\n.legacy-svc .form-success{display:none;text-align:center;padding:36px 24px;background:rgba(240,169,59,.09);border:1px solid rgba(240,169,59,.28);border-radius:5px}\n.legacy-svc .fs-ico{font-size:2rem;margin-bottom:10px}\n.legacy-svc .fs-title{font-family:var(--fd);font-size:1.6rem;font-weight:800;text-transform:uppercase;color:#fff;margin-bottom:8px}\n.legacy-svc .fs-msg{font-size:13.5px;color:rgba(255,255,255,.62)}\n\n/* в”Ђв”Ђ Responsive в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n@media(max-width:1024px){\n  .legacy-svc .svc-grid{grid-template-columns:repeat(2,1fr)}\n  .legacy-svc .vess-grid{grid-template-columns:repeat(3,1fr)}\n  .legacy-svc .ch-grid{grid-template-columns:repeat(2,1fr)}\n  .legacy-svc .stats-inner{grid-template-columns:repeat(2,1fr)}\n  .legacy-svc .stat-item:nth-child(2){border-right:none}\n  .legacy-svc .cert-cards-grid{grid-template-columns:repeat(3,1fr)}\n  .legacy-svc .ind-grid{grid-template-columns:repeat(2,1fr)}\n}\n@media(max-width:768px){\n  .legacy-svc{--xl:68px}\n  .legacy-svc .hero{padding:68px 0 56px}\n  .legacy-svc .why-spec-grid{grid-template-columns:1fr 1fr}\n  .legacy-svc .svc-grid{grid-template-columns:1fr}\n  .legacy-svc .vess-grid{grid-template-columns:repeat(2,1fr)}\n  .legacy-svc .pos-grid{grid-template-columns:1fr}\n  .legacy-svc .proc-grid{grid-template-columns:1fr}\n  .legacy-svc .cert-cards-grid{grid-template-columns:repeat(2,1fr)}\n  .legacy-svc .emg-inner{grid-template-columns:1fr;gap:40px}\n  .legacy-svc .ch-grid{grid-template-columns:1fr}\n  .legacy-svc .ben-grid{grid-template-columns:1fr}\n  .legacy-svc .ind-grid{grid-template-columns:1fr}\n  .legacy-svc .cta-grid{grid-template-columns:1fr;gap:48px}\n  .legacy-svc .frow{grid-template-columns:1fr}\n}\n@media(max-width:480px){\n  .legacy-svc .vess-grid{grid-template-columns:repeat(2,1fr)}\n  .legacy-svc .why-spec-grid{grid-template-columns:1fr}\n  .legacy-svc .cert-cards-grid{grid-template-columns:repeat(2,1fr)}\n  .legacy-svc .stats-inner{grid-template-columns:repeat(2,1fr)}\n}\n@media(prefers-reduced-motion:reduce){\n  .legacy-svc *, .legacy-svc *::before, .legacy-svc *::after{transition:none!important;animation:none!important}\n}",
  "emergency-crew": "/* в”Ђв”Ђ TOKEN SYSTEM в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n  .legacy-svc {\n    --navy:       #062a30;\n    --navy-mid:   #07343a;\n    --navy-light: #0c4d56;\n    --steel:      #0e6e78;\n    --horizon:    #2a8a94;\n    --alert:      #f0a93b;\n    --alert-dim:  #d68a1c;\n    --amber:      #f6b53f;\n    --ice:        #e0eeea;\n    --white:      #FFFFFF;\n    --muted:      #6aa9b0;\n    --body-text:  #d8e7e3;\n    --border:     rgba(42,138,148,0.25);\n\n    --display: 'Barlow Condensed', sans-serif;\n    --body:    'Inter', sans-serif;\n    --copy:    'Barlow', sans-serif;\n  }\n\n  .legacy-svc *, .legacy-svc *::before, .legacy-svc *::after { box-sizing: border-box; margin: 0; padding: 0; }\n\n  .legacy-svc { scroll-behavior: smooth; }\n\n  .legacy-svc {\n    background: var(--navy);\n    color: var(--body-text);\n    font-family: var(--body);\n    font-size: 16px;\n    line-height: 1.7;\n    -webkit-font-smoothing: antialiased;\n  }\n\n  /* в”Ђв”Ђ SIGNATURE: ALERT TICKER в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n  .legacy-svc .alert-ticker {\n    background: var(--alert);\n    padding: 10px 0;\n    overflow: hidden;\n    position: relative;\n  }\n  .legacy-svc .alert-ticker::before {\n    content: '';\n    position: absolute; left: 0; top: 0; bottom: 0; width: 60px;\n    background: linear-gradient(to right, var(--alert), transparent);\n    z-index: 2;\n  }\n  .legacy-svc .alert-ticker::after {\n    content: '';\n    position: absolute; right: 0; top: 0; bottom: 0; width: 60px;\n    background: linear-gradient(to left, var(--alert), transparent);\n    z-index: 2;\n  }\n  .legacy-svc .ticker-track {\n    display: flex;\n    gap: 0;\n    animation: ticker 28s linear infinite;\n    white-space: nowrap;\n  }\n  .legacy-svc .ticker-item {\n    font-family: var(--display);\n    font-weight: 700;\n    font-size: 13px;\n    letter-spacing: 0.12em;\n    text-transform: uppercase;\n    color: #fff;\n    padding: 0 32px;\n  }\n  .legacy-svc .ticker-item span {\n    color: rgba(255,255,255,0.55);\n    margin-right: 32px;\n  }\n  @keyframes ticker {\n    0%   { transform: translateX(0); }\n    100% { transform: translateX(-50%); }\n  }\n\n  /* в”Ђв”Ђ STANDBY PULSE BADGE в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n  .legacy-svc .standby-badge {\n    display: inline-flex;\n    align-items: center;\n    gap: 8px;\n    background: rgba(240,169,59,0.12);\n    border: 1px solid rgba(240,169,59,0.45);\n    border-radius: 3px;\n    padding: 6px 14px;\n    font-family: var(--display);\n    font-size: 12px;\n    font-weight: 700;\n    letter-spacing: 0.14em;\n    text-transform: uppercase;\n    color: var(--alert);\n    margin-bottom: 28px;\n  }\n  .legacy-svc .pulse-dot {\n    width: 8px; height: 8px;\n    background: var(--alert);\n    border-radius: 50%;\n    animation: pulse 1.4s ease-in-out infinite;\n  }\n  @keyframes pulse {\n    0%, 100% { opacity: 1; transform: scale(1); }\n    50%       { opacity: 0.4; transform: scale(0.7); }\n  }\n\n  /* в”Ђв”Ђ LAYOUT в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n  .legacy-svc .container { max-width: 1180px; margin: 0 auto; padding: 0 32px; }\n  .legacy-svc .container--narrow { max-width: 860px; margin: 0 auto; padding: 0 32px; }\n\n  .legacy-svc section { padding: 90px 0; }\n  .legacy-svc section + section { border-top: 1px solid var(--border); }\n\n  /* в”Ђв”Ђ HERO в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n  .legacy-svc .hero {\n    background:\n      radial-gradient(ellipse 80% 60% at 60% 50%, rgba(42,138,148,0.12) 0%, transparent 70%),\n      linear-gradient(175deg, var(--navy-mid) 0%, var(--navy) 100%);\n    padding: 100px 0 90px;\n    position: relative;\n    overflow: hidden;\n  }\n  .legacy-svc .hero::after {\n    content: '';\n    position: absolute;\n    bottom: 0; left: 0; right: 0;\n    height: 1px;\n    background: linear-gradient(to right, transparent, var(--horizon), transparent);\n  }\n  /* grid lines background */\n  .legacy-svc .hero-grid {\n    position: absolute; inset: 0;\n    background-image:\n      linear-gradient(rgba(42,138,148,0.06) 1px, transparent 1px),\n      linear-gradient(90deg, rgba(42,138,148,0.06) 1px, transparent 1px);\n    background-size: 60px 60px;\n    pointer-events: none;\n  }\n  .legacy-svc .hero-content { position: relative; z-index: 1; }\n  .legacy-svc .hero-eyebrow {\n    font-family: var(--display);\n    font-size: 12px;\n    font-weight: 700;\n    letter-spacing: 0.18em;\n    text-transform: uppercase;\n    color: var(--horizon);\n    margin-bottom: 24px;\n  }\n  .legacy-svc .hero h1 {\n    font-family: var(--display);\n    font-size: clamp(42px, 6vw, 82px);\n    font-weight: 800;\n    line-height: 1.0;\n    text-transform: uppercase;\n    color: var(--white);\n    letter-spacing: -0.01em;\n    margin-bottom: 28px;\n  }\n  .legacy-svc .hero h1 em {\n    font-style: normal;\n    color: var(--alert);\n  }\n  .legacy-svc .hero-lead {\n    font-family: var(--copy);\n    font-size: 18px;\n    line-height: 1.65;\n    color: var(--body-text);\n    max-width: 640px;\n    margin-bottom: 48px;\n  }\n  .legacy-svc .hero-cta-group { display: flex; gap: 16px; flex-wrap: wrap; }\n  .legacy-svc .btn-primary {\n    display: inline-flex;\n    align-items: center;\n    gap: 10px;\n    background: var(--alert);\n    color: #fff;\n    font-family: var(--display);\n    font-size: 15px;\n    font-weight: 700;\n    letter-spacing: 0.08em;\n    text-transform: uppercase;\n    padding: 16px 32px;\n    border-radius: 3px;\n    text-decoration: none;\n    transition: background 0.2s;\n  }\n  .legacy-svc .btn-primary:hover { background: var(--alert-dim); }\n  .legacy-svc .btn-ghost {\n    display: inline-flex;\n    align-items: center;\n    gap: 10px;\n    background: transparent;\n    border: 1px solid var(--horizon);\n    color: var(--ice);\n    font-family: var(--display);\n    font-size: 15px;\n    font-weight: 700;\n    letter-spacing: 0.08em;\n    text-transform: uppercase;\n    padding: 16px 32px;\n    border-radius: 3px;\n    text-decoration: none;\n    transition: border-color 0.2s, color 0.2s;\n  }\n  .legacy-svc .btn-ghost:hover { border-color: var(--ice); color: #fff; }\n\n  /* hero stat strip */\n  .legacy-svc .hero-stats {\n    display: flex;\n    gap: 0;\n    margin-top: 72px;\n    border-top: 1px solid var(--border);\n    padding-top: 40px;\n    flex-wrap: wrap;\n  }\n  .legacy-svc .stat-item {\n    flex: 1;\n    min-width: 160px;\n    padding-right: 40px;\n  }\n  .legacy-svc .stat-item + .stat-item {\n    padding-left: 40px;\n    border-left: 1px solid var(--border);\n  }\n  .legacy-svc .stat-number {\n    font-family: var(--display);\n    font-size: 42px;\n    font-weight: 800;\n    color: var(--white);\n    line-height: 1;\n    margin-bottom: 6px;\n  }\n  .legacy-svc .stat-number span { color: var(--amber); }\n  .legacy-svc .stat-label {\n    font-size: 13px;\n    color: var(--muted);\n    text-transform: uppercase;\n    letter-spacing: 0.08em;\n    font-family: var(--display);\n    font-weight: 600;\n  }\n\n  /* в”Ђв”Ђ SECTION LABELS в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n  .legacy-svc .section-eyebrow {\n    font-family: var(--display);\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: 0.2em;\n    text-transform: uppercase;\n    color: var(--horizon);\n    margin-bottom: 14px;\n  }\n  .legacy-svc .section-title {\n    font-family: var(--display);\n    font-size: clamp(30px, 4vw, 48px);\n    font-weight: 800;\n    text-transform: uppercase;\n    color: var(--white);\n    line-height: 1.1;\n    letter-spacing: -0.01em;\n    margin-bottom: 20px;\n  }\n  .legacy-svc .section-lead {\n    font-family: var(--copy);\n    font-size: 17px;\n    color: var(--body-text);\n    max-width: 620px;\n    margin-bottom: 56px;\n    line-height: 1.7;\n  }\n\n  /* в”Ђв”Ђ WHY IT MATTERS в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n  .legacy-svc .why-grid {\n    display: grid;\n    grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));\n    gap: 2px;\n  }\n  .legacy-svc .why-card {\n    background: var(--navy-mid);\n    padding: 36px 32px;\n    border: 1px solid var(--border);\n    border-radius: 4px;\n    transition: border-color 0.2s, background 0.2s;\n  }\n  .legacy-svc .why-card:hover {\n    background: var(--navy-light);\n    border-color: var(--horizon);\n  }\n  .legacy-svc .why-icon {\n    width: 42px; height: 42px;\n    background: rgba(42,138,148,0.15);\n    border-radius: 6px;\n    display: flex; align-items: center; justify-content: center;\n    margin-bottom: 18px;\n    font-size: 20px;\n  }\n  .legacy-svc .why-card h3 {\n    font-family: var(--display);\n    font-size: 18px;\n    font-weight: 700;\n    text-transform: uppercase;\n    color: var(--white);\n    letter-spacing: 0.02em;\n    margin-bottom: 10px;\n  }\n  .legacy-svc .why-card p {\n    font-size: 14px;\n    line-height: 1.65;\n    color: var(--body-text);\n  }\n\n  /* в”Ђв”Ђ SOLUTIONS в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n  .legacy-svc .solutions-bg { background: var(--navy-mid); }\n  .legacy-svc .solutions-grid {\n    display: grid;\n    grid-template-columns: repeat(auto-fill, minmax(320px, 1fr));\n    gap: 24px;\n  }\n  .legacy-svc .solution-card {\n    background: var(--navy);\n    border: 1px solid var(--border);\n    border-left: 3px solid var(--horizon);\n    padding: 32px;\n    border-radius: 4px;\n    transition: border-left-color 0.2s;\n  }\n  .legacy-svc .solution-card:hover { border-left-color: var(--alert); }\n  .legacy-svc .solution-card h3 {\n    font-family: var(--display);\n    font-size: 17px;\n    font-weight: 700;\n    text-transform: uppercase;\n    color: var(--ice);\n    letter-spacing: 0.04em;\n    margin-bottom: 12px;\n  }\n  .legacy-svc .solution-card p { font-size: 14px; color: var(--body-text); line-height: 1.65; }\n\n  /* в”Ђв”Ђ CREW POSITIONS TABLE в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n  .legacy-svc .positions-tabs {\n    display: flex;\n    gap: 4px;\n    margin-bottom: 32px;\n    flex-wrap: wrap;\n  }\n  .legacy-svc .tab-btn {\n    background: var(--navy-mid);\n    border: 1px solid var(--border);\n    color: var(--muted);\n    font-family: var(--display);\n    font-size: 13px;\n    font-weight: 700;\n    text-transform: uppercase;\n    letter-spacing: 0.1em;\n    padding: 10px 22px;\n    border-radius: 3px;\n    cursor: pointer;\n    transition: all 0.2s;\n  }\n  .legacy-svc .tab-btn.active, .legacy-svc .tab-btn:hover {\n    background: var(--horizon);\n    border-color: var(--horizon);\n    color: #fff;\n  }\n  .legacy-svc .tab-panel { display: none; }\n  .legacy-svc .tab-panel.active { display: grid; grid-template-columns: repeat(auto-fill, minmax(260px, 1fr)); gap: 16px; }\n  .legacy-svc .position-item {\n    background: var(--navy-mid);\n    border: 1px solid var(--border);\n    border-radius: 4px;\n    padding: 22px 24px;\n  }\n  .legacy-svc .position-rank {\n    font-family: var(--display);\n    font-size: 16px;\n    font-weight: 700;\n    text-transform: uppercase;\n    color: var(--white);\n    letter-spacing: 0.04em;\n    margin-bottom: 8px;\n  }\n  .legacy-svc .position-desc { font-size: 13px; color: var(--muted); line-height: 1.55; }\n\n  /* в”Ђв”Ђ VESSEL TYPES в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n  .legacy-svc .vessels-bg { background: var(--navy-mid); }\n  .legacy-svc .vessel-grid {\n    display: grid;\n    grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));\n    gap: 16px;\n  }\n  .legacy-svc .vessel-card {\n    background: var(--navy);\n    border: 1px solid var(--border);\n    border-radius: 4px;\n    padding: 28px 24px;\n    text-align: center;\n    transition: border-color 0.2s, transform 0.2s;\n  }\n  .legacy-svc .vessel-card:hover { border-color: var(--amber); transform: translateY(-3px); }\n  .legacy-svc .vessel-emoji { font-size: 32px; margin-bottom: 12px; display: block; }\n  .legacy-svc .vessel-name {\n    font-family: var(--display);\n    font-size: 15px;\n    font-weight: 700;\n    text-transform: uppercase;\n    letter-spacing: 0.05em;\n    color: var(--white);\n    margin-bottom: 8px;\n  }\n  .legacy-svc .vessel-desc { font-size: 12px; color: var(--muted); }\n\n  /* в”Ђв”Ђ PROCESS в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n  .legacy-svc .process-steps { display: flex; flex-direction: column; gap: 0; }\n  .legacy-svc .process-step {\n    display: grid;\n    grid-template-columns: 72px 1fr;\n    gap: 0;\n    position: relative;\n  }\n  .legacy-svc .step-number-col {\n    display: flex;\n    flex-direction: column;\n    align-items: center;\n    padding-top: 4px;\n  }\n  .legacy-svc .step-num {\n    width: 44px; height: 44px;\n    background: var(--navy-light);\n    border: 2px solid var(--horizon);\n    border-radius: 50%;\n    display: flex; align-items: center; justify-content: center;\n    font-family: var(--display);\n    font-size: 16px;\n    font-weight: 800;\n    color: var(--horizon);\n    flex-shrink: 0;\n  }\n  .legacy-svc .step-line {\n    width: 2px;\n    flex: 1;\n    background: linear-gradient(to bottom, var(--horizon), transparent);\n    min-height: 40px;\n    margin-top: 8px;\n  }\n  .legacy-svc .process-step:last-child .step-line { display: none; }\n  .legacy-svc .step-content { padding: 0 0 44px 28px; }\n  .legacy-svc .step-content h3 {\n    font-family: var(--display);\n    font-size: 19px;\n    font-weight: 700;\n    text-transform: uppercase;\n    color: var(--white);\n    letter-spacing: 0.04em;\n    margin-bottom: 8px;\n  }\n  .legacy-svc .step-content p { font-size: 14px; color: var(--body-text); line-height: 1.65; }\n\n  /* в”Ђв”Ђ COMPLIANCE в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n  .legacy-svc .compliance-grid {\n    display: grid;\n    grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));\n    gap: 16px;\n  }\n  .legacy-svc .compliance-card {\n    background: var(--navy-mid);\n    border: 1px solid var(--border);\n    border-top: 3px solid var(--amber);\n    border-radius: 4px;\n    padding: 28px 24px;\n  }\n  .legacy-svc .compliance-card h3 {\n    font-family: var(--display);\n    font-size: 20px;\n    font-weight: 800;\n    text-transform: uppercase;\n    color: var(--amber);\n    letter-spacing: 0.04em;\n    margin-bottom: 8px;\n  }\n  .legacy-svc .compliance-card p { font-size: 13px; color: var(--body-text); line-height: 1.6; }\n\n  /* в”Ђв”Ђ USP/WHY CHOOSE в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n  .legacy-svc .usp-bg { background: var(--navy-mid); }\n  .legacy-svc .usp-grid {\n    display: grid;\n    grid-template-columns: repeat(3, 1fr);\n    gap: 2px;\n  }\n  @media (max-width: 768px) { .legacy-svc .usp-grid { grid-template-columns: 1fr; } }\n  .legacy-svc .usp-item {\n    background: var(--navy);\n    padding: 36px 32px;\n    border: 1px solid var(--border);\n  }\n  .legacy-svc .usp-item h3 {\n    font-family: var(--display);\n    font-size: 18px;\n    font-weight: 700;\n    text-transform: uppercase;\n    letter-spacing: 0.04em;\n    color: var(--ice);\n    margin-bottom: 10px;\n  }\n  .legacy-svc .usp-item p { font-size: 14px; color: var(--body-text); line-height: 1.65; }\n  .legacy-svc .usp-num {\n    font-family: var(--display);\n    font-size: 40px;\n    font-weight: 800;\n    color: rgba(42,138,148,0.2);\n    line-height: 1;\n    margin-bottom: 12px;\n  }\n\n  /* в”Ђв”Ђ BENEFITS в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n  .legacy-svc .benefits-list {\n    display: grid;\n    grid-template-columns: 1fr 1fr;\n    gap: 20px;\n  }\n  @media (max-width: 640px) { .legacy-svc .benefits-list { grid-template-columns: 1fr; } }\n  .legacy-svc .benefit-item {\n    display: flex;\n    gap: 16px;\n    align-items: flex-start;\n  }\n  .legacy-svc .benefit-check {\n    width: 28px; height: 28px;\n    background: rgba(42,138,148,0.2);\n    border: 1px solid var(--horizon);\n    border-radius: 50%;\n    display: flex; align-items: center; justify-content: center;\n    flex-shrink: 0;\n    color: var(--horizon);\n    font-size: 13px;\n    margin-top: 2px;\n  }\n  .legacy-svc .benefit-item h4 {\n    font-family: var(--display);\n    font-size: 16px;\n    font-weight: 700;\n    text-transform: uppercase;\n    color: var(--white);\n    letter-spacing: 0.04em;\n    margin-bottom: 6px;\n  }\n  .legacy-svc .benefit-item p { font-size: 14px; color: var(--body-text); line-height: 1.6; }\n\n  /* в”Ђв”Ђ INDUSTRIES в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n  .legacy-svc .industries-bg { background: var(--navy-mid); }\n  .legacy-svc .industry-grid {\n    display: grid;\n    grid-template-columns: repeat(auto-fill, minmax(240px, 1fr));\n    gap: 16px;\n  }\n  .legacy-svc .industry-card {\n    background: var(--navy);\n    border: 1px solid var(--border);\n    border-radius: 4px;\n    padding: 28px;\n    transition: border-color 0.2s;\n  }\n  .legacy-svc .industry-card:hover { border-color: var(--horizon); }\n  .legacy-svc .industry-tag {\n    font-family: var(--display);\n    font-size: 11px;\n    font-weight: 700;\n    text-transform: uppercase;\n    letter-spacing: 0.15em;\n    color: var(--horizon);\n    margin-bottom: 10px;\n  }\n  .legacy-svc .industry-card h3 {\n    font-family: var(--display);\n    font-size: 18px;\n    font-weight: 700;\n    text-transform: uppercase;\n    color: var(--white);\n    letter-spacing: 0.04em;\n    margin-bottom: 10px;\n  }\n  .legacy-svc .industry-card p { font-size: 13px; color: var(--body-text); line-height: 1.6; }\n\n  /* в”Ђв”Ђ FAQ в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n  .legacy-svc .faq-list { display: flex; flex-direction: column; gap: 8px; }\n  .legacy-svc .faq-item {\n    background: var(--navy-mid);\n    border: 1px solid var(--border);\n    border-radius: 4px;\n    overflow: hidden;\n  }\n  .legacy-svc .faq-question {\n    width: 100%;\n    background: none;\n    border: none;\n    padding: 22px 28px;\n    text-align: left;\n    cursor: pointer;\n    display: flex;\n    justify-content: space-between;\n    align-items: center;\n    gap: 16px;\n  }\n  .legacy-svc .faq-q-text {\n    font-family: var(--display);\n    font-size: 16px;\n    font-weight: 700;\n    text-transform: uppercase;\n    letter-spacing: 0.04em;\n    color: var(--white);\n  }\n  .legacy-svc .faq-icon {\n    width: 24px; height: 24px;\n    background: rgba(42,138,148,0.15);\n    border-radius: 50%;\n    display: flex; align-items: center; justify-content: center;\n    flex-shrink: 0;\n    color: var(--horizon);\n    font-size: 16px;\n    transition: transform 0.25s, background 0.2s;\n  }\n  .legacy-svc .faq-item.open .faq-icon { transform: rotate(45deg); background: var(--horizon); color: #fff; }\n  .legacy-svc .faq-answer {\n    display: none;\n    padding: 0 28px 22px;\n    font-size: 14px;\n    color: var(--body-text);\n    line-height: 1.7;\n    border-top: 1px solid var(--border);\n    padding-top: 18px;\n  }\n  .legacy-svc .faq-item.open .faq-answer { display: block; }\n\n  /* в”Ђв”Ђ CTA в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n  .legacy-svc .cta-section {\n    background:\n      radial-gradient(ellipse 70% 80% at 50% 50%, rgba(240,169,59,0.1) 0%, transparent 70%),\n      var(--navy-mid);\n    border-top: 1px solid rgba(240,169,59,0.25);\n    position: relative;\n    overflow: hidden;\n  }\n  .legacy-svc .cta-section::before {\n    content: 'SOS';\n    position: absolute;\n    right: -40px; top: 50%; transform: translateY(-50%);\n    font-family: var(--display);\n    font-size: 300px;\n    font-weight: 800;\n    color: rgba(240,169,59,0.04);\n    line-height: 1;\n    pointer-events: none;\n    user-select: none;\n  }\n  .legacy-svc .cta-inner { position: relative; z-index: 1; text-align: center; max-width: 760px; margin: 0 auto; }\n  .legacy-svc .cta-inner .section-title { margin-bottom: 16px; }\n  .legacy-svc .cta-inner p {\n    font-family: var(--copy);\n    font-size: 17px;\n    color: var(--body-text);\n    margin-bottom: 48px;\n    line-height: 1.7;\n  }\n  .legacy-svc .cta-form {\n    background: var(--navy);\n    border: 1px solid var(--border);\n    border-radius: 6px;\n    padding: 40px;\n    text-align: left;\n  }\n  .legacy-svc .form-grid {\n    display: grid;\n    grid-template-columns: 1fr 1fr;\n    gap: 16px;\n    margin-bottom: 16px;\n  }\n  @media (max-width: 600px) { .legacy-svc .form-grid { grid-template-columns: 1fr; } }\n  .legacy-svc .form-field { display: flex; flex-direction: column; gap: 7px; }\n  .legacy-svc .form-field label {\n    font-family: var(--display);\n    font-size: 11px;\n    font-weight: 700;\n    text-transform: uppercase;\n    letter-spacing: 0.12em;\n    color: var(--muted);\n  }\n  .legacy-svc .form-field input, .legacy-svc .form-field select, .legacy-svc .form-field textarea {\n    background: var(--navy-mid);\n    border: 1px solid var(--border);\n    border-radius: 3px;\n    padding: 12px 16px;\n    font-family: var(--body);\n    font-size: 14px;\n    color: var(--white);\n    outline: none;\n    transition: border-color 0.2s;\n    width: 100%;\n  }\n  .legacy-svc .form-field input::placeholder, .legacy-svc .form-field textarea::placeholder { color: var(--steel); }\n  .legacy-svc .form-field input:focus, .legacy-svc .form-field select:focus, .legacy-svc .form-field textarea:focus { border-color: var(--horizon); }\n  .legacy-svc .form-field select option { background: var(--navy-mid); }\n  .legacy-svc .form-field textarea { resize: vertical; min-height: 90px; }\n  .legacy-svc .form-field.full { grid-column: 1 / -1; }\n  .legacy-svc .form-submit {\n    display: flex;\n    align-items: center;\n    justify-content: space-between;\n    flex-wrap: wrap;\n    gap: 20px;\n    margin-top: 24px;\n    padding-top: 24px;\n    border-top: 1px solid var(--border);\n  }\n  .legacy-svc .form-note { font-size: 13px; color: var(--muted); }\n  .legacy-svc .form-note strong { color: var(--amber); font-weight: 600; }\n\n  /* в”Ђв”Ђ DIVIDER в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n  .legacy-svc .hr-signal {\n    display: flex;\n    align-items: center;\n    gap: 16px;\n    margin: 20px 0 56px;\n  }\n  .legacy-svc .hr-signal::before, .legacy-svc .hr-signal::after {\n    content: '';\n    flex: 1;\n    height: 1px;\n    background: var(--border);\n  }\n  .legacy-svc .hr-signal span {\n    font-family: var(--display);\n    font-size: 11px;\n    font-weight: 700;\n    letter-spacing: 0.16em;\n    text-transform: uppercase;\n    color: var(--steel);\n  }\n\n  /* в”Ђв”Ђ RAPID CAPABILITY в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n  .legacy-svc .rapid-grid {\n    display: grid;\n    grid-template-columns: 1fr 1fr;\n    gap: 40px;\n    align-items: start;\n  }\n  @media (max-width: 768px) { .legacy-svc .rapid-grid { grid-template-columns: 1fr; } }\n  .legacy-svc .rapid-list { display: flex; flex-direction: column; gap: 20px; }\n  .legacy-svc .rapid-item {\n    display: flex;\n    gap: 20px;\n    align-items: flex-start;\n    padding: 24px;\n    background: var(--navy-mid);\n    border: 1px solid var(--border);\n    border-radius: 4px;\n  }\n  .legacy-svc .rapid-icon {\n    font-size: 24px;\n    flex-shrink: 0;\n    margin-top: 2px;\n  }\n  .legacy-svc .rapid-item h4 {\n    font-family: var(--display);\n    font-size: 16px;\n    font-weight: 700;\n    text-transform: uppercase;\n    letter-spacing: 0.04em;\n    color: var(--white);\n    margin-bottom: 6px;\n  }\n  .legacy-svc .rapid-item p { font-size: 13px; color: var(--body-text); line-height: 1.6; }\n\n  .legacy-svc .status-panel {\n    background: var(--navy-mid);\n    border: 1px solid var(--border);\n    border-radius: 6px;\n    overflow: hidden;\n    position: sticky;\n    top: 32px;\n  }\n  .legacy-svc .status-header {\n    background: var(--navy-light);\n    padding: 18px 24px;\n    display: flex;\n    align-items: center;\n    gap: 12px;\n    border-bottom: 1px solid var(--border);\n  }\n  .legacy-svc .status-header span {\n    font-family: var(--display);\n    font-size: 13px;\n    font-weight: 700;\n    text-transform: uppercase;\n    letter-spacing: 0.1em;\n    color: var(--ice);\n  }\n  .legacy-svc .status-rows { padding: 8px 0; }\n  .legacy-svc .status-row {\n    display: flex;\n    justify-content: space-between;\n    align-items: center;\n    padding: 14px 24px;\n    border-bottom: 1px solid var(--border);\n  }\n  .legacy-svc .status-row:last-child { border-bottom: none; }\n  .legacy-svc .status-row-label {\n    font-family: var(--display);\n    font-size: 13px;\n    font-weight: 600;\n    text-transform: uppercase;\n    letter-spacing: 0.06em;\n    color: var(--muted);\n  }\n  .legacy-svc .status-badge {\n    font-family: var(--display);\n    font-size: 11px;\n    font-weight: 700;\n    text-transform: uppercase;\n    letter-spacing: 0.1em;\n    padding: 4px 10px;\n    border-radius: 3px;\n  }\n  .legacy-svc .badge-green  { background: rgba(39,174,96,0.15);  color: #4CAF50; border: 1px solid rgba(39,174,96,0.3); }\n  .legacy-svc .badge-yellow { background: rgba(246,181,63,0.15); color: var(--amber); border: 1px solid rgba(246,181,63,0.3); }\n  .legacy-svc .badge-blue   { background: rgba(42,138,148,0.15); color: var(--horizon); border: 1px solid rgba(42,138,148,0.3); }\n\n  /* в”Ђв”Ђ RESPONSIVE в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ */\n  @media (max-width: 768px) {\n    .legacy-svc section { padding: 60px 0; }\n    .legacy-svc .container, .legacy-svc .container--narrow { padding: 0 20px; }\n    .legacy-svc .usp-grid { grid-template-columns: 1fr; }\n    .legacy-svc .hero-stats { gap: 24px; }\n    .legacy-svc .stat-item + .stat-item { padding-left: 0; border-left: none; border-top: 1px solid var(--border); padding-top: 24px; }\n    .legacy-svc .cta-form { padding: 24px 20px; }\n  }\n\n  @media (prefers-reduced-motion: reduce) {\n    .legacy-svc .ticker-track { animation: none; }\n    .legacy-svc .pulse-dot { animation: none; }\n  }",
};
